                  {loading ? (
                    <tr><td colSpan={5} className="text-center py-20 text-slate-500">{t('loading')}</td></tr>
                  ) : paginatedHistory.length === 0 ? (
                    <tr><td colSpan={5} className="text-center py-20 text-slate-500">No records found.</td></tr>
                  ) : (
                    paginatedHistory.map((adm) => (
                      <tr key={adm.id}>
                        <td className="px-6 py-4 whitespace-nowrap font-bold text-slate-800 dark:text-white">{adm.patientName}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-300">
                          <div>Room {adm.roomNumber}</div>
                          <div className="text-xs text-slate-400">Dr. {adm.doctorName}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">
                          <div>Entry: {new Date(adm.entry_date).toLocaleDateString()}</div>
                          <div className="text-xs">{adm.actual_discharge_date ? `Discharged: ${new Date(adm.actual_discharge_date).toLocaleDateString()}` : 'Active'}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-center">{getStatusBadge(adm.status)}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-right">
                          <Button size="sm" variant="outline" icon={Eye} onClick={() => handleViewDetails(adm.id, true)}>View</Button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>

            {paginatedHistory.length > 0 && (
              <div className="flex justify-between items-center p-4 border-t border-slate-200 dark:border-slate-700">
                  <span className="text-sm text-slate-500">{t('patients_pagination_showing')} {paginatedHistory.length} {t('patients_pagination_of')} {filteredHistory.length}</span>
                  <div className="flex gap-2">
                      <Button size="sm" variant="secondary" onClick={() => setHistoryCurrentPage(p => Math.max(1, p - 1))} disabled={historyCurrentPage === 1} icon={ChevronLeft}>Prev</Button>
                      <Button size="sm" variant="secondary" onClick={() => setHistoryCurrentPage(p => Math.min(historyTotalPages, p + 1))} disabled={historyCurrentPage === historyTotalPages} icon={ChevronRight}>Next</Button>
                  </div>
              </div>
            )}
          </Card>
        </div>
      )}

      {/* --- ALL MODALS --- */}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

// Import translation files directly using relative paths
import enTranslations from '../locales/en.json';
import arTranslations from '../locales/ar.json';

type Language = 'en' | 'ar';

const translationsData: Record<Language, Record<string, string>> = {
  en: enTranslations,
  ar: arTranslations,
};

interface TranslationContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: string, options?: Record<string, string | number>) => string;
}

const TranslationContext = createContext<TranslationContextType | undefined>(undefined);

export const TranslationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguageState] = useState<Language>(() => {
    const storedLang = localStorage.getItem('language');
    // Basic validation to ensure stored language is one of the supported ones
    if (storedLang === 'en' || storedLang === 'ar') {
      return storedLang;
    }
    return 'en'; // Default to English
  });

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('language', lang);
  };

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  const t = useCallback((key: string, options?: Record<string, string | number>): string => {
    const translations = translationsData[language];
    const text = translations[key] || key; // Fallback to key if not found
    if (options && typeof text === 'string') {
      return Object.entries(options).reduce((acc, [k, v]) => {
        return acc.replace(new RegExp(`{${k}}`, 'g'), String(v));
      }, text);
    }
    return text;
  }, [language]);

  return (
    <TranslationContext.Provider value={{ language, setLanguage, t }}>
      {children}
    </TranslationContext.Provider>
  );
};

export const useTranslation = () => {
  const context = useContext(TranslationContext);
  if (!context) throw new Error('useTranslation must be used within a TranslationProvider');
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

type Language = 'en' | 'ar';

interface TranslationContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: string, options?: Record<string, string | number>) => string;
  loading: boolean;
}

const TranslationContext = createContext<TranslationContextType | undefined>(undefined);

export const TranslationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguageState] = useState<Language>(() => {
    const storedLang = localStorage.getItem('language');
    if (storedLang === 'en' || storedLang === 'ar') {
      return storedLang as Language;
    }
    return 'en';
  });
  const [translations, setTranslations] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadTranslations = async () => {
      setLoading(true);
      try {
        const response = await fetch(`/locales/${language}.json`);
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        setTranslations(data);
      } catch (error) {
        console.error(`Failed to load translations for ${language}:`, error);
        setTranslations({}); // Fallback to empty on error
      } finally {
        setLoading(false);
      }
    };
    loadTranslations();
  }, [language]);

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('language', lang);
  };

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  const t = useCallback((key: string, options?: Record<string, string | number>): string => {
    const text = translations[key] || key; // Fallback to key
    if (options && typeof text === 'string') {
      return Object.entries(options).reduce((acc, [k, v]) => {
        return acc.replace(new RegExp(`{${k}}`, 'g'), String(v));
      }, text);
    }
    return text;
  }, [translations]);

  const value = { language, setLanguage, t, loading };

  return (
    <TranslationContext.Provider value={value}>
      {children}
    </TranslationContext.Provider>
  );
};

export const useTranslation = () => {
  const context = useContext(TranslationContext);
  if (!context) throw new Error('useTranslation must be used within a TranslationProvider');
  return context;
};

