import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';

export const Admissions = () => {
  const { accent } = useTheme();
  const { t, language } = useTranslation();
  const { user: currentUser } = useAuth();
  const navigate = useNavigate();
  const [beds, setBeds] = useState<any[]>([]);
  const [activeAdmissions, setActiveAdmissions] = useState<any[]>([]);
  const [allAdmissions, setAllAdmissions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [patients, setPatients] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  const [activeTab, setActiveTab] = useState<'ward' | 'history'>('ward');

  // History Filters & Pagination
  const [historySearchTerm, setHistorySearchTerm] = useState('');
  const [historyStatusFilter, setHistoryStatusFilter] = useState('all');
  const [historyCurrentPage, setHistoryCurrentPage] = useState(1);
  const [historyItemsPerPage, setHistoryItemsPerPage] = useState(10);

  // Advanced Process State
  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  // Modals
  const [isCareModalOpen, setIsCareModalOpen] = useState(false); // For Active Patients & History View
  const [isAdmitModalOpen, setIsAdmitModalOpen] = useState(false); // For New Reservation
  const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false); // For Reserved -> Active

  // Confirmation Dialog State
  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    action: () => void;
    type?: 'danger' | 'warning' | 'info';
  }>({ isOpen: false, title: '', message: '', action: () => {} });

  // Selection States
  const [selectedAdmission, setSelectedAdmission] = useState<any | null>(null);
  const [selectedBedForAdmission, setSelectedBedForAdmission] = useState<any>(null);
  const [inpatientDetails, setInpatientDetails] = useState<any>(null);
  const [careTab, setCareTab] = useState<'overview' | 'notes' | 'discharge'>('overview');
  const [isHistoryView, setIsHistoryView] = useState(false); // Differentiates Care Modal usage

  // Search State for Admission
  const [patientSearchTerm, setPatientSearchTerm] = useState('');
  const [showPatientResults, setShowPatientResults] = useState(false);
  const [selectedPatientForAdmission, setSelectedPatientForAdmission] = useState<any>(null);

  // Forms
  const [admitForm, setAdmitForm] = useState({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: '', notes: '' });
  const [noteForm, setNoteForm] = useState({ note: '', bp: '', temp: '', pulse: '', resp: '' });
  const [dischargeForm, setDischargeForm] = useState({ notes: '', status: 'Recovered' });

  const loadData = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [bedsData, admissionsData, allAdmissionsData, patientsData, staffData] = await Promise.all([
        api.getBeds(),
        api.getActiveAdmissions(),
        api.getAllAdmissions(),
        api.getPatients(),
        api.getStaff(),
      ]);
      setBeds(bedsData);
      setActiveAdmissions(admissionsData);
      setAllAdmissions(allAdmissionsData);
      setPatients(patientsData);
      setStaff(staffData);
    } catch (e) {
      console.error(e);
    } finally {
      if (!silent) setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const calculateDays = (dateString: string, endDateString?: string) => {
    if (!dateString) return 0;
    const start = new Date(dateString);
    const end = endDateString ? new Date(endDateString) : new Date();
    const diff = Math.abs(end.getTime() - start.getTime());
    return Math.ceil(diff / (1000 * 60 * 60 * 24)) || 1;
  };

  const handleViewDetails = async (admissionId: number, isHistory: boolean = false) => {
    try {
        setProcessStatus('processing');
        setProcessMessage('Loading admission record...');
        const details = await api.getInpatientDetails(admissionId);
        setInpatientDetails(details);
        setCareTab('overview');
        setIsHistoryView(isHistory);
        setIsCareModalOpen(true);
    } catch (e) {
        console.error("Failed to load details", e);
        setProcessMessage("Failed to load admission details.");
    } finally {
        setProcessStatus('idle');
    }
  };

  const handleBedClick = async (bed: any) => {
    // 1. RESERVED BED -> CONFIRMATION
    if (bed.status === 'reserved') {
      const admission = activeAdmissions.find(a => a.bedId === bed.id && a.status === 'reserved');
      if (admission) {
        setSelectedAdmission(admission);
        setIsConfirmModalOpen(true);
      }
      return;
    }

    // 2. OCCUPIED BED -> PATIENT CARE
    if (bed.status === 'occupied') {
      const admission = activeAdmissions.find(a => a.bedId === bed.id && a.status === 'active');
      if (admission) {
        await handleViewDetails(admission.id);
      }
      return;
    }

    // 3. AVAILABLE BED -> NEW ADMISSION (RESERVATION)
    if (bed.status === 'available') {
      setSelectedBedForAdmission(bed);
      setAdmitForm({ 
        patientId: '', 
        doctorId: '', 
        entryDate: new Date().toISOString().split('T')[0], 
        deposit: bed.costPerDay.toString(), 
        notes: '' 
      });
      setPatientSearchTerm('');
      setSelectedPatientForAdmission(null);
      setIsAdmitModalOpen(true);
      return;
    }

    // 4. CLEANING BED -> MARK AVAILABLE
    if (bed.status === 'cleaning') {
      setConfirmState({
        isOpen: true,
        title: 'Mark as Cleaned',
        message: 'Has this room been cleaned and prepared for the next patient?',
        type: 'info',
        action: async () => {
          try {
            await api.markBedClean(bed.id);
            loadData(true);
          } catch (e) { console.error(e); }
        }
      });
    }
  };

  const handleAdmitSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBedForAdmission || !selectedPatientForAdmission) return;

    setProcessStatus('processing');
    setProcessMessage(t('processing'));

    try {
      await api.createAdmission({
        patientId: selectedPatientForAdmission.id,
        bedId: selectedBedForAdmission.id,
        doctorId: parseInt(admitForm.doctorId),
        entryDate: admitForm.entryDate,
        deposit: parseFloat(admitForm.deposit),
        notes: admitForm.notes
      });

      setProcessStatus('success');
      setProcessMessage(t('patients_process_success_admission'));
      await loadData(true);

      setTimeout(() => {
        setIsAdmitModalOpen(false);
        setProcessStatus('idle');
      }, 2000);
    } catch (err: any) {
       setProcessStatus('error');
       setProcessMessage(err.response?.data?.error || 'Failed to admit patient.');
    }
  };

  const handleCancelReservation = async () => {
    if (!selectedAdmission) return;
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_cancel_title'),
      message: t('admissions_dialog_cancel_message'),
      action: async () => {
        setIsConfirmModalOpen(false);
        setProcessStatus('processing');
        setProcessMessage('Cancelling reservation...');
        try {
          await api.cancelAdmission(selectedAdmission.id);
          setProcessStatus('success');
          setProcessMessage(t('admissions_toast_cancel_success'));
          await loadData(true);
          setTimeout(() => setProcessStatus('idle'), 1500);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Failed to cancel reservation.');
        }
      }
    });
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inpatientDetails || !currentUser) return;
    try {
      await api.addInpatientNote(inpatientDetails.id, {
        doctorId: currentUser.id, 
        note: noteForm.note,
        vitals: { bp: noteForm.bp, temp: noteForm.temp, pulse: noteForm.pulse, resp: noteForm.resp }
      });
      const details = await api.getInpatientDetails(inpatientDetails.id);
      setInpatientDetails(details);
      setNoteForm({ note: '', bp: '', temp: '', pulse: '', resp: '' });
    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || 'Failed to add note');
    }
  };

  // --- DISCHARGE WORKFLOW ---
  const currentStayCost = inpatientDetails?.estimatedBill ?? 0;
  const depositPaid = inpatientDetails?.depositPaid ?? 0;
  const currentStayDue = currentStayCost - depositPaid;
  const otherBillsDue = inpatientDetails?.unpaidBills?.reduce((acc: number, bill: any) => acc + (bill.total_amount - bill.paid_amount), 0) ?? 0;
  const balanceDue = currentStayDue + otherBillsDue;

  const handleGenerateSettlementBill = () => {
    if (!inpatientDetails) return;
    setConfirmState({
      isOpen: true,
      title: 'Generate Settlement Bill',
      message: `This will finalize accommodation charges and create a single bill for the total outstanding balance of $${balanceDue.toFixed(2)}. The patient will not be discharged until this new bill is paid. Continue?`,
      type: 'info',
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Generating settlement bill...');
        try {
          await api.generateSettlementBill(inpatientDetails.id);
          setProcessStatus('success');
          setProcessMessage('Settlement bill created. Please go to Billing to process payment.');
          const details = await api.getInpatientDetails(inpatientDetails.id);
          setInpatientDetails(details);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Failed to generate bill.');
        } finally {
          setTimeout(() => setProcessStatus('idle'), 3000);
        }
      }
    });
  };

  const handleDischarge = () => {
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_discharge_title'),
      message: balanceDue < 0 
        ? `The patient has a credit of $${Math.abs(balanceDue).toFixed(2)}. This amount will need to be refunded separately. Proceed with discharge?`
        : t('admissions_dialog_discharge_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage(t('processing'));
        try {
          await api.dischargePatient(inpatientDetails.id, {
            dischargeNotes: dischargeForm.notes,
            dischargeStatus: dischargeForm.status
          });
          setProcessStatus('success');
          setProcessMessage('Patient discharged successfully. Bed marked for cleaning.');
          await loadData(true);
          setTimeout(() => {
            setIsCareModalOpen(false);
            setProcessStatus('idle');
          }, 2000);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Discharge failed. Ensure all bills are paid.');
        }
      }
    });
  };

  // --- Helper for Patient Search ---
  const filteredPatientsForAdmission = patients.filter(p => {
    const matchesSearch = 
      p.fullName.toLowerCase().includes(patientSearchTerm.toLowerCase()) || 
      p.patientId.toLowerCase().includes(patientSearchTerm.toLowerCase()) || 
      p.phone.includes(patientSearchTerm);
    const isAlreadyAdmitted = activeAdmissions.some(a => a.patient_id === p.id);
    return matchesSearch && !isAlreadyAdmitted && p.type !== 'inpatient';
  });

  // --- History View Logic ---
  const filteredHistory = useMemo(() => {
    return allAdmissions.filter(adm => {
        const matchesSearch = 
            adm.patientName.toLowerCase().includes(historySearchTerm.toLowerCase()) ||
            adm.roomNumber.toLowerCase().includes(historySearchTerm.toLowerCase()) ||
            (adm.doctorName && adm.doctorName.toLowerCase().includes(historySearchTerm.toLowerCase()));

        const matchesStatus = historyStatusFilter === 'all' || adm.status === historyStatusFilter;

        return matchesSearch && matchesStatus;
    });
  }, [allAdmissions, historySearchTerm, historyStatusFilter]);

  const historyTotalPages = Math.ceil(filteredHistory.length / historyItemsPerPage);
  const paginatedHistory = filteredHistory.slice((historyCurrentPage - 1) * historyItemsPerPage, historyCurrentPage * historyItemsPerPage);

  const getStatusBadge = (status: string) => {
    switch(status) {
        case 'active': return <Badge color="green">Active</Badge>;
        case 'discharged': return <Badge color="gray">Discharged</Badge>;
        case 'cancelled': return <Badge color="red">Cancelled</Badge>;
        case 'reserved': return <Badge color="blue">Reserved</Badge>;
        default: return <Badge color="gray">{status}</Badge>;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('admissions_title')}</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">{t('admissions_subtitle')}</p>
        </div>
      </div>

      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-fit mb-6">
          <button
              onClick={() => setActiveTab('ward')}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'ward' ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200'}`}
          >
              <Bed size={18} /> Ward View
          </button>
          <button
              onClick={() => setActiveTab('history')}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200'}`}
          >
              <HistoryIcon size={18} /> History
          </button>
      </div>

      {activeTab === 'ward' && (
        <div className="animate-in fade-in">
          <div className="flex gap-3 text-xs font-medium flex-wrap mb-6">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 rounded-lg border border-green-100 dark:border-green-800">
              <div className="w-2 h-2 rounded-full bg-green-500"></div> {t('admissions_legend_available')}
            </div>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400 rounded-lg border border-blue-100 dark:border-blue-800">
              <div className="w-2 h-2 rounded-full bg-blue-500"></div> {t('admissions_legend_reserved')}
            </div>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 rounded-lg border border-red-100 dark:border-red-800">
              <div className="w-2 h-2 rounded-full bg-red-500"></div> {t('admissions_legend_occupied')}
            </div>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-400 rounded-lg border border-purple-100 dark:border-purple-800">
              <div className="w-2 h-2 rounded-full bg-purple-500"></div> Cleaning
            </div>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-yellow-50 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-400 rounded-lg border border-yellow-100 dark:border-yellow-800">
              <div className="w-2 h-2 rounded-full bg-yellow-500"></div> {t('admissions_legend_maintenance')}
            </div>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
            {loading ? <p className="col-span-full text-center py-10 text-gray-500">{t('admissions_loading')}</p> : 
            beds.map(bed => {
              const admission = activeAdmissions.find(a => a.bedId === bed.id);
              const isOccupied = bed.status === 'occupied';
              const isReserved = bed.status === 'reserved';
              const isMaintenance = bed.status === 'maintenance';
              const isCleaning = bed.status === 'cleaning';
              const doctorName = admission?.doctorName || 'Unassigned';
              return (
                <div 
                  key={bed.id} 
                  onClick={() => handleBedClick(bed)}
                  className={`
                    relative p-4 rounded-xl border-2 transition-all cursor-pointer group flex flex-col justify-between h-40 shadow-sm hover:shadow-md
                    ${isOccupied 
                      ? 'bg-white dark:bg-slate-800 border-red-100 dark:border-red-900/50 hover:border-red-300' 
                      : isReserved
                        ? 'bg-white dark:bg-slate-800 border-blue-100 dark:border-blue-900/50 hover:border-blue-300'
                        : isCleaning
                          ? 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800 hover:border-purple-400'
                          : isMaintenance 
                            ? 'bg-yellow-50 dark:bg-yellow-900/20 border-yellow-200 dark:border-yellow-800' 
                            : 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800 hover:border-green-400'}
                  `}
                >
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className="font-bold text-slate-800 dark:text-white text-lg">{bed.roomNumber}</h3>
                      <p className="text-xs text-slate-500 dark:text-slate-400">{bed.type} / ${bed.costPerDay}</p>
                    </div>
                    <div className={`w-3 h-3 rounded-full mt-1 
                      ${isOccupied ? 'bg-red-500' : isReserved ? 'bg-blue-500' : isCleaning ? 'bg-purple-500' : isMaintenance ? 'bg-yellow-500' : 'bg-green-500'}`}
                    />
                  </div>
                  <div>
                    {isOccupied || isReserved ? (
                      <>
                        <p className="text-sm font-bold text-slate-900 dark:text-white truncate">{admission?.patientName}</p>
                        <div className="flex justify-between items-center text-xs text-slate-500 dark:text-slate-400 mt-1">
                          <span>{t('admissions_bed_doctor', {name: doctorName})}</span>
                          <span className="font-mono">{t('admissions_bed_days', {count: calculateDays(admission?.entry_date || admission?.entryDate)})}</span>
                        </div>
                      </>
                    ) : isCleaning ? (
                       <div className="text-center">
                          <Sparkles size={24} className="text-purple-500 mx-auto mb-1" />
                          <p className="text-xs font-bold text-purple-700 dark:text-purple-300">Cleaning</p>
                       </div>
                    ) : isMaintenance ? (
                       <div className="text-center">
                          <Wrench size={24} className="text-yellow-600 mx-auto mb-1" />
                          <p className="text-xs font-bold text-yellow-700 dark:text-yellow-300">{t('admissions_bed_maintenance')}</p>
                       </div>
                    ) : (
                       <div className="text-center opacity-70 group-hover:opacity-100 transition-opacity">
                          <CheckCircle size={32} className="text-green-500 mx-auto mb-1"/>
                          <p className="text-xs font-bold text-green-800 dark:text-green-300">{t('admissions_bed_available')}</p>
                       </div>
                    )}
                  </div>

                  {isReserved && (
                    <div className="absolute inset-x-0 bottom-4 px-4">
                       <div className="text-center text-xs font-bold text-blue-600 dark:text-blue-300 bg-blue-50 dark:bg-blue-900/30 p-1.5 rounded-lg border border-blue-100 dark:border-blue-800">
                         {t('admissions_bed_payment_pending')}
                       </div>
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="animate-in fade-in">
          <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-visible z-10">
            <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex flex-col md:flex-row gap-4 items-center">
              <div className="relative w-full md:w-96">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input 
                  type="text"
                  placeholder="Search patient, room, or doctor..." 
                  className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                  value={historySearchTerm}
                  onChange={e => { setHistorySearchTerm(e.target.value); setHistoryCurrentPage(1); }}
                />
              </div>
              <select 
                className="pl-3 pr-8 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                value={historyStatusFilter}
                onChange={e => { setHistoryStatusFilter(e.target.value); setHistoryCurrentPage(1); }}
              >
                <option value="all">All Statuses</option>
                <option value="discharged">Discharged</option>
                <option value="cancelled">Cancelled</option>
                <option value="active">Active</option>
                <option value="reserved">Reserved</option>
              </select>
            </div>

            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-slate-100 dark:divide-slate-700">
                <thead className="bg-slate-50 dark:bg-slate-900">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Patient</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Room/Doctor</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Dates</th>
                    <th className="px-6 py-3 text-center text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">Actions</th>
                  </tr>
                </thead>
                <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                  {loading ? (
                    <tr><td colSpan={5} className="text-center py-20 text-slate-500">{t('loading')}</td></tr>
                  ) : paginatedHistory.length === 0 ? (
                    <tr><td colSpan={5} className="text-center py-20 text-slate-500">No records found.</td></tr>
                  ) : (
                    paginatedHistory.map((adm) => (
                      <tr key={adm.id}>
                        <td className="px-6 py-4 whitespace-nowrap font-bold text-slate-800 dark:text-white">{adm.patientName}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-300">
                          <div>Room {adm.roomNumber}</div>
                          <div className="text-xs text-slate-400">Dr. {adm.doctorName}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">
                          <div>Entry: {new Date(adm.entry_date).toLocaleDateString()}</div>
                          <div className="text-xs">{adm.actual_discharge_date ? `Discharged: ${new Date(adm.actual_discharge_date).toLocaleDateString()}` : 'Active'}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-center">{getStatusBadge(adm.status)}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-right">
                          <Button size="sm" variant="outline" icon={Eye} onClick={() => handleViewDetails(adm.id, true)}>View</Button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>

            {paginatedHistory.length > 0 && (
              <div className="flex justify-between items-center p-4 border-t border-slate-200 dark:border-slate-700">
                  <span className="text-sm text-slate-500">{t('patients_pagination_showing')} {paginatedHistory.length} {t('patients_pagination_of')} {filteredHistory.length}</span>
                  <div className="flex gap-2">
                      <Button size="sm" variant="secondary" onClick={() => setHistoryCurrentPage(p => Math.max(1, p - 1))} disabled={historyCurrentPage === 1} icon={ChevronLeft}>Prev</Button>
                      <Button size="sm" variant="secondary" onClick={() => setHistoryCurrentPage(p => Math.min(historyTotalPages, p + 1))} disabled={historyCurrentPage === historyTotalPages} icon={ChevronRight}>Next</Button>
                  </div>
              </div>
            )}
          </Card>
        </div>
      )}

      {/* --- ALL MODALS --- */}
    </div>
  );
};

const express = require('express');
const router = express.Router();
const multer = require('multer');
// Security: Limit upload size to 50MB to prevent disk exhaustion
const upload = multer({ 
  dest: 'uploads/',
  limits: { fileSize: 50 * 1024 * 1024 }
});

const { authenticateToken, authorizeRoles } = require('../middleware/auth');
const { Permissions } = require('../utils/rbac_backend_mirror');
const { validate, schemas } = require('../middleware/validation');

const authController = require('../controllers/auth.controller');
const patientController = require('../controllers/patient.controller');
const staffController = require('../controllers/staff.controller');
