    const settings = rows.reduce((acc, row) => {
      acc[row.key] = row.value;
      return acc;
    }, {});
    res.json(settings);
  } catch (err) { res.status(500).json({ error: err.message }); }
};

exports.getPublicSettings = (req, res) => {
