  const [selectedPatientForAdmission, setSelectedPatientForAdmission] = useState<any>(null);

  // Forms
  const [admitForm, setAdmitForm] = useState({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: '', notes: '' });
  const [noteForm, setNoteForm] = useState({ note: '', bp: '', temp: '', pulse: '', resp: '' });
  const [dischargeForm, setDischargeForm] = useState({ notes: '', status: 'Recovered' });

  const loadData = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [bedsData, admissionsData, patientsData, staffData] = await Promise.all([
        api.getBeds(),
        api.getActiveAdmissions(),
        api.getPatients(),
        api.getStaff(),
      ]);
      setBeds(bedsData);
      setActiveAdmissions(admissionsData);
      setPatients(patientsData);
      setStaff(staffData);
    } catch (e) {
      console.error(e);
    } finally {
      if (!silent) setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const calculateDays = (dateString: string, endDateString?: string) => {
    if (!dateString) return 0;
    const start = new Date(dateString);
    const end = endDateString ? new Date(endDateString) : new Date();
    const diff = Math.abs(end.getTime() - start.getTime());
    return Math.ceil(diff / (1000 * 60 * 60 * 24)) || 1;
  };

  const handleViewDetails = async (admissionId: number) => {
    try {
        setProcessStatus('processing');
        setProcessMessage('Loading admission record...');
        const details = await api.getInpatientDetails(admissionId);
        setInpatientDetails(details);
        setCareTab('overview');
        setIsCareModalOpen(true);
    } catch (e) {
        console.error("Failed to load details", e);
        setProcessMessage("Failed to load admission details.");
    } finally {
        setProcessStatus('idle');
    }
  };

  const handleBedClick = async (bed: any) => {
    if (bed.status === 'reserved') {
      const admission = activeAdmissions.find(a => a.bedId === bed.id && a.status === 'reserved');
      if (admission) {
        setSelectedAdmission(admission);
        setIsConfirmModalOpen(true);
      }
      return;
    }

    if (bed.status === 'occupied') {
      const admission = activeAdmissions.find(a => a.bedId === bed.id && a.status === 'active');
      if (admission) {
        await handleViewDetails(admission.id);
      }
      return;
    }

    if (bed.status === 'available') {
      setSelectedBedForAdmission(bed);
      setAdmitForm({ 
        patientId: '', 
        doctorId: '', 
        entryDate: new Date().toISOString().split('T')[0], 
        deposit: bed.costPerDay.toString(), 
        notes: '' 
      });
      setPatientSearchTerm('');
      setSelectedPatientForAdmission(null);
      setIsAdmitModalOpen(true);
      return;
    }

    if (bed.status === 'cleaning') {
      setConfirmState({
        isOpen: true,
        title: 'Mark as Cleaned',
        message: 'Has this room been cleaned and prepared for the next patient?',
        type: 'info',
        action: async () => {
          try {
            await api.markBedClean(bed.id);
            loadData(true);
          } catch (e) { console.error(e); }
        }
      });
    }
  };

  const handleAdmitSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBedForAdmission || !selectedPatientForAdmission) return;

    setProcessStatus('processing');
    setProcessMessage(t('processing'));

    try {
      await api.createAdmission({
        patientId: selectedPatientForAdmission.id,
        bedId: selectedBedForAdmission.id,
        doctorId: parseInt(admitForm.doctorId),
        entryDate: admitForm.entryDate,
        deposit: parseFloat(admitForm.deposit),
        notes: admitForm.notes
      });

      setProcessStatus('success');
      setProcessMessage(t('patients_process_success_admission'));
      await loadData(true);

      setTimeout(() => {
        setIsAdmitModalOpen(false);
        setProcessStatus('idle');
      }, 2000);
    } catch (err: any) {
       setProcessStatus('error');
       setProcessMessage(err.response?.data?.error || 'Failed to admit patient.');
    }
  };

  const handleConfirmAdmission = async () => {
    if (!selectedAdmission) return;

    setProcessStatus('processing');
    setProcessMessage('Confirming admission...');

    try {
      await api.confirmAdmissionDeposit(selectedAdmission.id);

      setProcessStatus('success');
      setProcessMessage('Admission confirmed. Patient is now active.');

      await loadData(true); // Refresh data

      setTimeout(() => {
        setIsConfirmModalOpen(false); // Close the confirmation modal
        setProcessStatus('idle');
      }, 1500);
    } catch (err: any) {
       setProcessStatus('error');
       setProcessMessage(err.response?.data?.error || 'Failed to confirm admission.');
    }
  };

  const handleCancelReservation = async () => {
    if (!selectedAdmission) return;
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_cancel_title'),
      message: t('admissions_dialog_cancel_message'),
      action: async () => {
        setIsConfirmModalOpen(false);
        setProcessStatus('processing');
        setProcessMessage('Cancelling reservation...');
        try {
          await api.cancelAdmission(selectedAdmission.id);
          setProcessStatus('success');
          setProcessMessage(t('admissions_toast_cancel_success'));
          await loadData(true);
          setTimeout(() => setProcessStatus('idle'), 1500);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Failed to cancel reservation.');
        }
      }
    });
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inpatientDetails || !currentUser) return;
    try {
      await api.addInpatientNote(inpatientDetails.id, {
        doctorId: currentUser.id, 
        note: noteForm.note,
        vitals: { bp: noteForm.bp, temp: noteForm.temp, pulse: noteForm.pulse, resp: noteForm.resp }
      });
      const details = await api.getInpatientDetails(inpatientDetails.id);
      setInpatientDetails(details);
      setNoteForm({ note: '', bp: '', temp: '', pulse: '', resp: '' });
    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || 'Failed to add note');
    }
  };

  const currentStayCost = inpatientDetails?.estimatedBill ?? 0;
  const depositPaid = inpatientDetails?.depositPaid ?? 0;
  const otherBillsDue = inpatientDetails?.unpaidBills?.reduce((acc: number, bill: any) => acc + (bill.total_amount - bill.paid_amount), 0) ?? 0;
  const balanceDue = (currentStayCost - depositPaid) + otherBillsDue;

  const handleGenerateSettlementBill = () => {
    if (!inpatientDetails) return;
    setConfirmState({
      isOpen: true,
      title: 'Generate Settlement Bill',
      message: `This will create a single bill for the total outstanding balance of $${balanceDue.toFixed(2)}. The patient cannot be discharged until this bill is paid. Continue?`,
      type: 'info',
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Generating settlement bill...');
        try {
          await api.generateSettlementBill(inpatientDetails.id);
          setProcessStatus('success');
          setProcessMessage('Settlement bill created. Please go to Billing to process payment.');
          const details = await api.getInpatientDetails(inpatientDetails.id);
          setInpatientDetails(details);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Failed to generate bill.');
        } finally {
          setTimeout(() => setProcessStatus('idle'), 3000);
        }
      }
    });
  };

  const handleDischarge = () => {
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_discharge_title'),
      message: balanceDue < 0 
        ? `The patient has a credit of $${Math.abs(balanceDue).toFixed(2)}. This amount will need to be refunded separately. Proceed with discharge?`
        : t('admissions_dialog_discharge_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage(t('processing'));
        try {
          await api.dischargePatient(inpatientDetails.id, {
            dischargeNotes: dischargeForm.notes,
            dischargeStatus: dischargeForm.status
          });
          setProcessStatus('success');
          setProcessMessage('Patient discharged successfully. Bed marked for cleaning.');
          await loadData(true);
          setTimeout(() => {
            setIsCareModalOpen(false);
            setProcessStatus('idle');
          }, 2000);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Discharge failed. Ensure all bills are paid.');
        }
      }
    });
  };

  const filteredPatientsForAdmission = patients.filter(p => {
    const matchesSearch = 
      p.fullName.toLowerCase().includes(patientSearchTerm.toLowerCase()) || 
      (p.patientId && p.patientId.toLowerCase().includes(patientSearchTerm.toLowerCase())) || 
      (p.phone && p.phone.includes(patientSearchTerm));
    const isAlreadyAdmitted = activeAdmissions.some(a => a.patient_id === p.id);
    return matchesSearch && !isAlreadyAdmitted && p.type !== 'inpatient';
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('admissions_title')}</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">{t('admissions_subtitle')}</p>
        </div>
      </div>

      <div className="flex gap-3 text-xs font-medium flex-wrap mb-2">
        <div className="flex items-center gap-2 px-3 py-1.5 bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 rounded-lg border border-green-100 dark:border-green-800">
          <div className="w-2 h-2 rounded-full bg-green-500"></div> {t('admissions_legend_available')}
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400 rounded-lg border border-blue-100 dark:border-blue-800">
          <div className="w-2 h-2 rounded-full bg-blue-500"></div> {t('admissions_legend_reserved')}
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 rounded-lg border border-red-100 dark:border-red-800">
          <div className="w-2 h-2 rounded-full bg-red-500"></div> {t('admissions_legend_occupied')}
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-400 rounded-lg border border-purple-100 dark:border-purple-800">
          <div className="w-2 h-2 rounded-full bg-purple-500"></div> Cleaning
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 bg-yellow-50 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-400 rounded-lg border border-yellow-100 dark:border-yellow-800">
          <div className="w-2 h-2 rounded-full bg-yellow-500"></div> {t('admissions_legend_maintenance')}
        </div>
      </div>
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
        {loading ? <p className="col-span-full text-center py-10 text-gray-500">{t('admissions_loading')}</p> : 
        beds.map(bed => {
          const admission = activeAdmissions.find(a => a.bedId === bed.id);
          const isOccupied = bed.status === 'occupied';
          const isReserved = bed.status === 'reserved';
          const isMaintenance = bed.status === 'maintenance';
          const isCleaning = bed.status === 'cleaning';
          const doctorName = admission?.doctorName || 'Unassigned';
          return (
            <div 
              key={bed.id} 
              onClick={() => handleBedClick(bed)}
              className={`
                relative p-4 rounded-xl border-2 transition-all cursor-pointer group flex flex-col h-48 shadow-sm hover:shadow-md
                ${isOccupied 
                  ? 'bg-white dark:bg-slate-800 border-red-100 dark:border-red-900/50 hover:border-red-300' 
                  : isReserved
                    ? 'bg-white dark:bg-slate-800 border-blue-100 dark:border-blue-900/50 hover:border-blue-300'
                    : isCleaning
                      ? 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800 hover:border-purple-400'
                      : isMaintenance 
                        ? 'bg-yellow-50 dark:bg-yellow-900/20 border-yellow-200 dark:border-yellow-800' 
                        : 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800 hover:border-green-400'}
              `}
            >
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="font-bold text-slate-800 dark:text-white text-lg leading-none">{bed.roomNumber}</h3>
                  <p className="text-[10px] text-slate-500 dark:text-slate-400 mt-1">{bed.type} / ${bed.costPerDay}</p>
                </div>
                <div className={`w-3 h-3 rounded-full shrink-0 
                  ${isOccupied ? 'bg-red-500' : isReserved ? 'bg-blue-500' : isCleaning ? 'bg-purple-500' : isMaintenance ? 'bg-yellow-500' : 'bg-green-500'}`}
                />
              </div>

              <div className="flex-1 flex flex-col justify-center items-center w-full">
                {isOccupied || isReserved ? (
                  <div className="w-full text-center">
                    <p className="text-sm font-bold text-slate-900 dark:text-white line-clamp-2 leading-tight mb-2 px-1" title={admission?.patientName}>
                        {admission?.patientName}
                    </p>
                    <div className="flex justify-between items-center text-[10px] text-slate-500 dark:text-slate-400 w-full px-1 border-t border-slate-100 dark:border-slate-700/50 pt-2 mt-1">
                      <span className="truncate max-w-[60%] text-left" title={doctorName}>{t('admissions_bed_doctor', {name: doctorName})}</span>
                      <span className="font-mono whitespace-nowrap">{t('admissions_bed_days', {count: calculateDays(admission?.entry_date || admission?.entryDate)})}</span>
                    </div>
                    {isReserved && (
                        <p className="text-[10px] font-bold text-blue-600 dark:text-blue-400 text-center mt-2 uppercase tracking-wider">
                            Pending
                        </p>
                    )}
                  </div>
                ) : isCleaning ? (
                   <div className="text-center">
                      <Sparkles size={32} className="text-purple-500 mx-auto mb-2" />
                      <p className="text-xs font-bold text-purple-700 dark:text-purple-300">Cleaning</p>
                   </div>
                ) : isMaintenance ? (
                   <div className="text-center">
                      <Wrench size={32} className="text-yellow-600 mx-auto mb-2" />
                      <p className="text-xs font-bold text-yellow-700 dark:text-yellow-300">{t('admissions_bed_maintenance')}</p>
                   </div>
                ) : (
                   <div className="text-center opacity-70 group-hover:opacity-100 transition-opacity">
                      <CheckCircle size={40} className="text-green-500 mx-auto mb-2"/>
                      <p className="text-sm font-bold text-green-800 dark:text-green-300">{t('admissions_bed_available')}</p>
                   </div>
                )}
              </div>
            </div>
          )
        })}
      </div>

      {/* --- ALL MODALS --- */}

      {/* Admit Patient Modal */}
      <Modal isOpen={isAdmitModalOpen} onClose={() => setIsAdmitModalOpen(false)} title={t('admissions_modal_reserve_title', { room: selectedBedForAdmission?.roomNumber })}>
        <form onSubmit={handleAdmitSubmit} className="space-y-4">
          <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg text-sm text-blue-700 dark:text-blue-300 border border-blue-100 dark:border-blue-800">
            {t('admissions_modal_reserve_note', { room: selectedBedForAdmission?.roomNumber })}
          </div>

          {!selectedPatientForAdmission ? (
            <div className="relative">
              <Input 
                label={t('patients_table_header_patient')} 
                placeholder={t('patients_search_placeholder')}
                value={patientSearchTerm}
                onChange={e => {setPatientSearchTerm(e.target.value); setShowPatientResults(true); }}
              />
              {showPatientResults && filteredPatientsForAdmission.length > 0 && (
                <div className="absolute z-10 w-full bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-lg mt-1 shadow-lg max-h-48 overflow-y-auto">
                  {filteredPatientsForAdmission.map(p => (
                    <div 
                      key={p.id} 
                      className="p-3 hover:bg-slate-50 dark:hover:bg-slate-600 cursor-pointer"
                      onClick={() => {
                        setSelectedPatientForAdmission(p);
                        setShowPatientResults(false);
                      }}
                    >
                      {p.fullName} ({p.patientId})
                    </div>
                  ))}
                </div>
              )}
            </div>
          ) : (
            <div>
              <label className="block text-sm font-semibold mb-1">{t('patients_table_header_patient')}</label>
              <div className="flex items-center justify-between p-3 bg-slate-100 dark:bg-slate-700 rounded-lg">
                <span className="font-medium">{selectedPatientForAdmission.fullName}</span>
                <button type="button" onClick={() => setSelectedPatientForAdmission(null)} className="text-xs text-red-500">Change</button>
              </div>
            </div>
          )}

          <Select label={t('patients_modal_action_assign_doctor')} required value={admitForm.doctorId} onChange={e => setAdmitForm({...admitForm, doctorId: e.target.value})}>
            <option value="">{t('patients_modal_action_select_doctor')}</option>
            {staff.filter(s => s.type === 'doctor').map(doc => <option key={doc.id} value={doc.id}>{doc.fullName}</option>)}
          </Select>

          <div className="grid grid-cols-2 gap-4">
            <Input label={t('patients_modal_action_admission_date')} type="date" required value={admitForm.entryDate} onChange={e => setAdmitForm({...admitForm, entryDate: e.target.value})} />
            <Input label={t('patients_modal_action_required_deposit')} type="number" required value={admitForm.deposit} onChange={e => setAdmitForm({...admitForm, deposit: e.target.value})} />
          </div>

          <Textarea label={t('admissions_care_admission_note')} rows={2} value={admitForm.notes} onChange={e => setAdmitForm({...admitForm, notes: e.target.value})} />

          <div className="flex justify-end pt-4 border-t border-slate-200 dark:border-slate-700 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsAdmitModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{t('admissions_modal_reserve_button')}</Button>
          </div>
        </form>
      </Modal>

      {/* Confirmation Modal for Reserved Beds */}
      <Modal isOpen={isConfirmModalOpen} onClose={() => setIsConfirmModalOpen(false)} title={selectedAdmission?.billStatus === 'paid' ? t('admissions_bed_manage') : t('admissions_modal_confirm_title')}>
        {selectedAdmission && (
          selectedAdmission.billStatus === 'paid' ? (
            <div className="space-y-4">
              <p className="text-sm text-slate-600 dark:text-slate-300" dangerouslySetInnerHTML={{ __html: t('admissions_confirm_message', { patient: selectedAdmission.patientName, cost: selectedAdmission.projected_cost }) }} />
              <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-center text-sm">
                  <span className="text-slate-500">{t('admissions_care_deposit_paid')}?</span>
                  <span className="font-bold text-lg text-emerald-600">${selectedAdmission.projected_cost}</span>
                </div>
              </div>
              <div className="flex justify-end gap-3 pt-4 border-t border-slate-200 dark:border-slate-700">
                <Button variant="danger" onClick={handleCancelReservation}>
                  {t('admissions_bed_cancel_reservation')}
                </Button>
                <Button onClick={handleConfirmAdmission}>
                  {t('admissions_confirm_and_admit')}
                </Button>
              </div>
            </div>
          ) : (
            <div className="space-y-4">
               <h3 className="font-bold text-slate-800 dark:text-white">{t('admissions_modal_confirm_subtitle')}</h3>
               <div className="p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-lg text-amber-800 dark:text-amber-300 text-sm">
                 <p className="font-bold mb-1">{t('admissions_payment_required')}</p>
                 <p>{t('admissions_modal_confirm_message')}</p>
               </div>
               <div className="flex justify-between items-center text-sm p-3 bg-slate-50 dark:bg-slate-900 rounded-lg">
                  <span>{t('patients_table_header_patient')}</span>
                  <span className="font-bold">{selectedAdmission.patientName}</span>
               </div>
               <div className="flex justify-end gap-3 pt-4 border-t border-slate-200 dark:border-slate-700">
                <Button variant="danger" onClick={handleCancelReservation}>{t('admissions_bed_cancel_reservation')}</Button>
                <Button onClick={() => { navigate('/billing'); setIsConfirmModalOpen(false); }}>{t('admissions_go_to_billing')}</Button>
              </div>
            </div>
          )
        )}
      </Modal>

      {/* Patient Care Modal */}
      <Modal isOpen={isCareModalOpen} onClose={() => setIsCareModalOpen(false)} title={t('admissions_modal_care_title')}>
        {inpatientDetails && (
          <div className="space-y-4">
            {/* Header */}
            <div className="p-4 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <h3 className="font-bold text-lg text-slate-900 dark:text-white">{inpatientDetails.patientName}</h3>
                        <div className="flex items-center gap-3 text-xs text-slate-500 dark:text-slate-400 mt-1">
                            <span>{inpatientDetails.age}yrs / {inpatientDetails.gender}</span>
                            <span>{t('Room')} {inpatientDetails.roomNumber}</span>
                            <span>Dr. {inpatientDetails.doctorName}</span>
                        </div>
                    </div>
                    <Badge color="green">Active</Badge>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-slate-200 dark:border-slate-700">
              <button onClick={() => setCareTab('overview')} className={`px-4 py-2 text-sm font-medium ${careTab === 'overview' ? 'border-b-2 border-primary-600 text-primary-600' : 'text-slate-500'}`}>{t('admissions_modal_care_tab_overview')}</button>
              <button onClick={() => setCareTab('notes')} className={`px-4 py-2 text-sm font-medium ${careTab === 'notes' ? 'border-b-2 border-primary-600 text-primary-600' : 'text-slate-500'}`}>{t('admissions_modal_care_tab_notes')}</button>
              <button onClick={() => setCareTab('discharge')} className={`px-4 py-2 text-sm font-medium ${careTab === 'discharge' ? 'border-b-2 border-primary-600 text-primary-600' : 'text-slate-500'}`}>{t('admissions_modal_care_tab_discharge')}</button>
            </div>

            {/* Overview Tab */}
            {careTab === 'overview' && (
                <div className="space-y-4 animate-in fade-in">
                    <h4 className="font-bold text-slate-600 dark:text-slate-300">{t('admissions_care_stay_details')}</h4>
                    <div className="grid grid-cols-3 gap-4 text-center">
                        <div className="bg-slate-50 dark:bg-slate-700/50 p-2 rounded-lg">
                            <p className="text-xs text-slate-400">{t('admissions_care_admission_date')}</p>
                            <p className="font-bold text-sm">{new Date(inpatientDetails.entry_date).toLocaleDateString()}</p>
                        </div>
                        <div className="bg-slate-50 dark:bg-slate-700/50 p-2 rounded-lg">
                            <p className="text-xs text-slate-400">{t('admissions_care_duration')}</p>
                            <p className="font-bold text-sm">{calculateDays(inpatientDetails.entry_date)} Days</p>
                        </div>
                        <div className="bg-slate-50 dark:bg-slate-700/50 p-2 rounded-lg">
                            <p className="text-xs text-slate-400">{t('admissions_care_daily_rate')}</p>
                            <p className="font-bold text-sm">${inpatientDetails.costPerDay}/day</p>
                        </div>
                    </div>
                    <div>
                        <h4 className="font-bold text-slate-600 dark:text-slate-300 mb-1">{t('admissions_care_admission_note')}</h4>
                        <p className="text-sm text-slate-500 italic p-2 bg-slate-50 dark:bg-slate-700/50 rounded-lg">{inpatientDetails.notes || t('admissions_care_no_initial_notes')}</p>
                    </div>
                </div>
            )}

            {/* Notes Tab */}
            {careTab === 'notes' && (
                <div className="space-y-4 animate-in fade-in max-h-96 overflow-y-auto pr-2">
                    <form onSubmit={handleAddNote} className="space-y-3 bg-slate-50 dark:bg-slate-900 p-4 rounded-xl border dark:border-slate-700">
                        <h4 className="font-bold text-slate-600 dark:text-slate-300">{t('admissions_care_add_note')}</h4>
                        <div className="grid grid-cols-4 gap-2">
                            <Input label={t('admissions_care_vitals_bp')} placeholder="120/80" value={noteForm.bp} onChange={e => setNoteForm({...noteForm, bp: e.target.value})} />
                            <Input label={t('admissions_care_vitals_temp')} placeholder="37.0" value={noteForm.temp} onChange={e => setNoteForm({...noteForm, temp: e.target.value})} />
                            <Input label={t('admissions_care_vitals_pulse')} placeholder="75" value={noteForm.pulse} onChange={e => setNoteForm({...noteForm, pulse: e.target.value})} />
                            <Input label={t('admissions_care_vitals_resp')} placeholder="16" value={noteForm.resp} onChange={e => setNoteForm({...noteForm, resp: e.target.value})} />
                        </div>
                        <Textarea placeholder={t('admissions_care_observations_placeholder')} rows={2} value={noteForm.note} onChange={e => setNoteForm({...noteForm, note: e.target.value})} />
                        <div className="text-right">
                            <Button size="sm" type="submit">{t('admissions_care_save_note_button')}</Button>
                        </div>
                    </form>
                    {inpatientDetails.notes.length === 0 ? <p className="text-sm text-slate-400 text-center py-4">{t('admissions_care_no_notes')}</p> : 
                     inpatientDetails.notes.map((note: any) => (
                         <div key={note.id} className="p-3 border-b dark:border-slate-700">
                             <div className="flex justify-between text-xs text-slate-400 mb-1">
                                 <span>Dr. {note.doctorName}</span>
                                 <span>{new Date(note.created_at).toLocaleString()}</span>
                             </div>
                             <p className="text-sm">{note.note}</p>
                             <div className="flex gap-4 text-xs mt-2 text-slate-500">
                                 <span>BP: {note.vitals?.bp}</span>
                                 <span>Temp: {note.vitals?.temp}°C</span>
                                 <span>Pulse: {note.vitals?.pulse}bpm</span>
                                 <span>Resp: {note.vitals?.resp}rpm</span>
                             </div>
                         </div>
                     ))
                    }
                </div>
            )}

            {/* Discharge Tab */}
            {careTab === 'discharge' && (
                <div className="space-y-4 animate-in fade-in">
                    <div className="p-4 bg-yellow-50 dark:bg-yellow-900/20 rounded-lg border border-yellow-200 dark:border-yellow-800 text-yellow-800 dark:text-yellow-300">
                        <h4 className="font-bold mb-1">{t('admissions_care_discharge_process')}</h4>
                        <p className="text-sm">{t('admissions_care_discharge_note')}</p>
                    </div>

                    <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl border dark:border-slate-700">
                        <h4 className="font-bold text-slate-700 dark:text-slate-300 mb-2">{t('admissions_modal_discharge_summary_title')}</h4>
                        <div className="space-y-1 text-sm">
                            <div className="flex justify-between"><span className="text-slate-500">{t('admissions_care_accommodation_cost')} ({inpatientDetails.daysStayed} days)</span> <span>+ ${currentStayCost.toFixed(2)}</span></div>
                            <div className="flex justify-between"><span className="text-slate-500">{t('admissions_care_deposit_paid')}</span> <span className="text-green-600">- ${depositPaid.toFixed(2)}</span></div>
                            {inpatientDetails.unpaidBills.map((bill: any) => (
                                <div key={bill.id} className="flex justify-between pl-4 text-orange-600"><span className="text-slate-500">Invoice #{bill.bill_number}</span> <span>+ ${(bill.total_amount - bill.paid_amount).toFixed(2)}</span></div>
                            ))}
                            <div className="flex justify-between font-bold text-lg pt-2 border-t mt-2"><span className="text-slate-700 dark:text-slate-200">{t('admissions_care_balance_due')}</span> <span className="text-red-600">${balanceDue.toFixed(2)}</span></div>
                        </div>
                    </div>

                    {balanceDue > 0.01 && (
                        <Button className="w-full" variant="outline" onClick={handleGenerateSettlementBill}>
                            {t('billing_generate_settlement_button')}
                        </Button>
                    )}

                    <form className="space-y-3 pt-4 border-t dark:border-slate-700">
                        <Select label={t('admissions_care_discharge_status')} value={dischargeForm.status} onChange={e => setDischargeForm({...dischargeForm, status: e.target.value})}>
                            <option value="Recovered">{t('admissions_care_discharge_status_recovered')}</option>
                            <option value="Transferred">{t('admissions_care_discharge_status_transferred')}</option>
                            <option value="Against Medical Advice">{t('admissions_care_discharge_status_ama')}</option>
                            <option value="Deceased">{t('admissions_care_discharge_status_deceased')}</option>
                        </Select>
                        <Textarea label={t('admissions_care_discharge_summary')} rows={2} value={dischargeForm.notes} onChange={e => setDischargeForm({...dischargeForm, notes: e.target.value})} />
                        <Button className="w-full" onClick={handleDischarge} disabled={balanceDue > 0.01}>
                            {balanceDue > 0.01 ? t('admissions_clear_due_balance', { balance: balanceDue.toFixed(2) }) : t('admissions_discharge_button')}
                        </Button>
                    </form>
                </div>
            )}
          </div>
        )}
      </Modal>

      {/* Generic Confirmation Dialog for Cleaning, etc. */}
      <ConfirmationDialog
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={() => {
          confirmState.action();
          setConfirmState({ ...confirmState, isOpen: false });
        }}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type || 'danger'}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Wrench, Settings as SettingsIcon, Building, Database, Trash2, Plus, Save, Edit, 
  Bed, Users, Loader2, CheckCircle, XCircle, AlertTriangle, Upload, Download, Server, 
  CreditCard, RotateCcw, Shield, Lock, Activity, RefreshCw, Briefcase, FlaskConical, Stethoscope 
} from 'lucide-react';
import { api } from '../services/api';
import { LabTestCatalog, NurseServiceCatalog, OperationCatalog, Bed as BedType, User, Role, TaxRate, PaymentMethod, InsuranceProvider } from '../types';
import { Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';

type CatalogType = 'dept' | 'spec' | 'lab' | 'nurse' | 'ops' | 'insurance' | 'banks';

const permissionGroups: Record<string, string[]> = {
  'permission_group_general': ['VIEW_DASHBOARD'],
  'permission_group_patients': ['VIEW_PATIENTS', 'MANAGE_PATIENTS', 'DELETE_PATIENTS'],
  'permission_group_appointments': ['VIEW_APPOINTMENTS', 'MANAGE_APPOINTMENTS', 'DELETE_APPOINTMENTS'],
  'permission_group_billing': ['VIEW_BILLING', 'MANAGE_BILLING', 'DELETE_BILLING'],
  'permission_group_hr': ['VIEW_HR', 'MANAGE_HR', 'DELETE_HR'],
  'permission_group_admissions': ['VIEW_ADMISSIONS', 'MANAGE_ADMISSIONS', 'DELETE_ADMISSIONS'],
  'permission_group_laboratory': ['VIEW_LABORATORY', 'MANAGE_LABORATORY', 'DELETE_LABORATORY'],
  'permission_group_operations': ['VIEW_OPERATIONS', 'MANAGE_OPERATIONS', 'DELETE_OPERATIONS'],
  'permission_group_reports': ['VIEW_REPORTS', 'MANAGE_REPORTS', 'VIEW_RECORDS'],
  'permission_group_system': ['VIEW_SETTINGS', 'MANAGE_SETTINGS', 'MANAGE_CONFIGURATION'],
};

const DiagnosticStat = ({ title, value, icon: Icon }: any) => (
  <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-700 flex items-center gap-4">
    <div className="p-3 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-primary-600">
       <Icon size={20} />
    </div>
    <div>
      <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{title}</p>
      <p className="text-lg font-bold text-slate-800 dark:text-white">{value}</p>
    </div>
  </div>
);

export const Configuration = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<'general' | 'beds' | 'catalogs' | 'users' | 'data' | 'financial' | 'diagnostics'>('general');
  const [loading, setLoading] = useState(true);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    action: () => void;
    type?: 'danger' | 'warning';
  }>({ isOpen: false, title: '', message: '', action: () => {} });

  // Data States
  const [settings, setSettings] = useState({ hospitalName: '', hospitalAddress: '', hospitalPhone: '', currency: '$' });
  const [healthData, setHealthData] = useState<any>(null);
  const [testLogs, setTestLogs] = useState<string[]>([]);
  const [isTesting, setIsTesting] = useState(false);
  const [users, setUsers] = useState<any[]>([]);
  const [rolePermissions, setRolePermissions] = useState<Record<string, string[]>>({});
  const [beds, setBeds] = useState<BedType[]>([]);
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [labTests, setLabTests] = useState<LabTestCatalog[]>([]);
  const [nurseServices, setNurseServices] = useState<NurseServiceCatalog[]>([]);
  const [operations, setOperations] = useState<OperationCatalog[]>([]);
  const [insuranceProviders, setInsuranceProviders] = useState<InsuranceProvider[]>([]);
  const [banks, setBanks] = useState<any[]>([]);
  const [taxes, setTaxes] = useState<TaxRate[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [restoreFile, setRestoreFile] = useState<File | null>(null);

  // Modal & Form States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [userForm, setUserForm] = useState<any>({});
  const [editingUserId, setEditingUserId] = useState<number | null>(null);
  const [userTabMode, setUserTabMode] = useState<'accounts' | 'roles'>('accounts');
  const [availableRoles] = useState<string[]>(['admin', 'manager', 'receptionist', 'technician', 'accountant', 'doctor', 'nurse', 'pharmacist', 'hr']);
  const [isBedModalOpen, setIsBedModalOpen] = useState(false);
  const [bedForm, setBedForm] = useState<Partial<BedType>>({});
  const [editingBedId, setEditingBedId] = useState<number | null>(null);
  const [catalogTab, setCatalogTab] = useState<CatalogType>('lab');
  const [isItemModalOpen, setIsItemModalOpen] = useState(false);
  const [itemFormData, setItemFormData] = useState<any>({});
  const [editingItemId, setEditingItemId] = useState<number | null>(null);
  const [financeForm, setFinanceForm] = useState<any>({});
  const [editingFinanceId, setEditingFinanceId] = useState<number | null>(null);
  const [financeTab, setFinanceTab] = useState<'tax' | 'payment'>('tax');
  const [isFinanceModalOpen, setIsFinanceModalOpen] = useState(false);


  const loadAllData = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [s, d, sp, b, l, n, o, ip, bn, u, t, p, rPerms] = await Promise.all([
        api.getSystemSettings(),
        api.getDepartments(),
        api.getSpecializations(),
        api.getBeds(), // Corrected from getConfigBeds
        api.getLabTests(),
        api.getNurseServices(),
        api.getOperations(),
        api.getInsuranceProviders(),
        api.getBanks(),
        api.getSystemUsers(),
        api.getTaxRates(),
        api.getPaymentMethods(),
        api.getRolePermissions()
      ]);
      if (s) setSettings(s);
      setDepartments(Array.isArray(d) ? d : []);
      setSpecializations(Array.isArray(sp) ? sp : []);
      setBeds(Array.isArray(b) ? b : []);
      setLabTests(Array.isArray(l) ? l : []);
      setNurseServices(Array.isArray(n) ? n : []);
      setOperations(Array.isArray(o) ? o : []);
      setInsuranceProviders(Array.isArray(ip) ? ip : []);
      setBanks(Array.isArray(bn) ? bn : []);
      setUsers(Array.isArray(u) ? u : []);
      setTaxes(Array.isArray(t) ? t : []);
      setPaymentMethods(Array.isArray(p) ? p : []);
      setRolePermissions(rPerms || {});
    } catch (e) {
      console.error("Failed to load config data", e);
    } finally {
      if (!silent) setLoading(false);
    }
  };

  useEffect(() => { loadAllData(); }, []);

  const handleAction = async (action: () => Promise<void>, successMsg: string) => {
    setProcessStatus('processing');
    setProcessMessage(t('processing'));
    try {
      await action();
      setProcessStatus('success');
      setProcessMessage(successMsg);
      await loadAllData(true);
      setTimeout(() => { setProcessStatus('idle'); }, 1500);
    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || e.message || 'An error occurred');
    }
  };

  // --- Handlers for each section ---

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      await api.updateSystemSettings(settings);
      if (settings.hospitalName) localStorage.setItem('hospital_name', settings.hospitalName);
    }, t('config_toast_settings_saved'));
  };

  // User Handlers
  const openUserModal = (user?: any) => {
    setEditingUserId(user ? user.id : null);
    setUserForm(user ? { ...user, password: '' } : { username: '', fullName: '', role: 'manager', isActive: true });
    setIsUserModalOpen(true);
  };
  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (editingUserId) await api.updateSystemUser(editingUserId, userForm);
      else await api.addSystemUser(userForm);
      setIsUserModalOpen(false);
    }, editingUserId ? t('config_toast_user_updated') : t('config_toast_user_created'));
  };
  const handleDeleteUser = (id: number) => {
    setConfirmState({
      isOpen: true, title: t('config_dialog_delete_user_title'), message: t('config_dialog_delete_user_msg'),
      action: () => handleAction(async () => await api.deleteSystemUser(id), t('config_toast_user_deleted'))
    });
  };
  const togglePermission = (role: string, permission: string) => {
    if (role === 'admin') return;
    const currentPerms = rolePermissions[role] || [];
    const updatedPerms = currentPerms.includes(permission) ? currentPerms.filter(p => p !== permission) : [...currentPerms, permission];
    setRolePermissions(prev => ({ ...prev, [role]: updatedPerms }));
  };
  const savePermissions = (role: string) => {
    handleAction(async () => await api.updateRolePermissions(role, rolePermissions[role] || []), t('config_toast_perms_updated', {role}));
  };

  // Bed Handlers
  const openBedModal = (bed?: BedType) => {
    setEditingBedId(bed ? bed.id : null);
    setBedForm(bed ? { ...bed } : { type: 'General', status: 'available', costPerDay: 0 });
    setIsBedModalOpen(true);
  };
  const handleBedSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (editingBedId) await api.updateBed(editingBedId, bedForm);
      else await api.addBed(bedForm);
      setIsBedModalOpen(false);
    }, editingBedId ? t('config_toast_room_updated') : t('config_toast_room_added'));
  };
  const handleDeleteBed = (id: number) => {
    setConfirmState({
      isOpen: true, title: t('config_dialog_delete_room_title'), message: t('config_dialog_delete_room_msg'),
      action: () => handleAction(async () => await api.deleteBed(id), t('config_toast_room_deleted'))
    });
  };

  // Catalog Handlers
  const openItemModal = (item?: any) => {
    setEditingItemId(item ? item.id : null);
    setItemFormData(item ? { ...item } : {});
    setIsItemModalOpen(true);
  };
  const handleItemSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const { apiAdd, apiUpdate } = catalogMetadata[catalogTab];
    handleAction(async () => {
      if (editingItemId) await apiUpdate(editingItemId, itemFormData);
      else await apiAdd(itemFormData);
      setIsItemModalOpen(false);
    }, editingItemId ? t('config_toast_item_updated') : t('config_toast_item_added'));
  };
  const handleDeleteItem = (id: number) => {
    const { apiDelete } = catalogMetadata[catalogTab];
    setConfirmState({
      isOpen: true, title: t('config_dialog_delete_item_title'), message: t('config_dialog_delete_item_msg'),
      action: () => handleAction(async () => await apiDelete(id), t('config_toast_item_deleted'))
    });
  };

  // Financial Handlers
  const openFinanceModal = (type: 'tax' | 'payment', item?: any) => {
    setFinanceTab(type);
    setEditingFinanceId(item ? item.id : null);
    setFinanceForm(item ? { ...item } : { name_en: '', name_ar: '', isActive: true });
    setIsFinanceModalOpen(true);
  };
  const handleFinanceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (financeTab === 'tax') {
        if (editingFinanceId) await api.updateTaxRate(editingFinanceId, financeForm);
        else await api.addTaxRate(financeForm);
      } else {
        if (editingFinanceId) await api.updatePaymentMethod(editingFinanceId, financeForm);
        else await api.addPaymentMethod(financeForm);
      }
      setIsFinanceModalOpen(false);
    }, editingFinanceId ? t('config_toast_item_updated') : t('config_toast_item_added'));
  };
  const handleDeleteFinance = (id: number, type: 'tax' | 'payment') => {
    setConfirmState({
      isOpen: true, title: t('config_dialog_delete_item_title'), message: t('config_dialog_delete_item_msg'),
      action: () => handleAction(async () => {
        if (type === 'tax') await api.deleteTaxRate(id);
        else await api.deletePaymentMethod(id);
      }, t('config_toast_item_deleted'))
    });
  };

  // Data Management Handlers
  const handleDownloadBackup = () => api.downloadBackup();
  const handleRestoreDatabase = (e: React.FormEvent) => {
    e.preventDefault();
    if (!restoreFile) return;
    setConfirmState({
      isOpen: true, title: t('config_dialog_overwrite_db_title'), message: t('config_dialog_overwrite_db_msg'), type: 'danger',
      action: () => handleAction(async () => {
        await api.restoreDatabase(restoreFile);
        setTimeout(() => window.location.reload(), 1500);
      }, t('config_toast_db_restored'))
    });
  };
  const handleResetDatabase = () => {
    setConfirmState({
      isOpen: true, title: t('config_dialog_factory_reset_title'), message: t('config_dialog_factory_reset_msg'), type: 'danger',
      action: () => handleAction(async () => {
          await api.resetDatabase();
          setTimeout(() => window.location.reload(), 2000);
      }, t('config_toast_db_reset'))
    });
  };

  // Diagnostics
  const runDiagnostics = async () => {
    setIsTesting(true);
    setTestLogs([t('config_diag_start')]);
    try {
      const addLog = (msg: string) => setTestLogs(prev => [...prev, msg]);
      await new Promise(res => setTimeout(res, 300));

      addLog(t('config_diag_check_api'));
      const health = await api.checkSystemHealth();
      setHealthData(health);
      addLog(t('config_diag_server_ok', {uptime: (health.uptime / 60).toFixed(1)}));

      await new Promise(res => setTimeout(res, 500));
      addLog(t('config_diag_verify_db'));
      addLog(t('config_diag_db_ok', {latency: health.database.latency}));

      await new Promise(res => setTimeout(res, 300));
      addLog(t('config_diag_all_ok'));
    } catch (e: any) {
      setTestLogs(prev => [...prev, t('config_diag_failed', {error: e.message})]);
      setHealthData({ status: 'error' });
    } finally {
      setIsTesting(false);
    }
  };

  // --- DYNAMIC CATALOG CONFIGURATION ---
  const catalogMetadata: Record<CatalogType, any> = {
    dept: {
      label: t('config_catalog_dept'),
      data: departments,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'description_en', label: t('config_field_desc_en'), type: 'textarea' },
        { name: 'description_ar', label: t('config_field_desc_ar'), type: 'textarea' },
      ],
      apiAdd: api.addDepartment, apiUpdate: api.updateDepartment, apiDelete: api.deleteDepartment
    },
    spec: {
      label: t('config_catalog_spec'),
      data: specializations,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'related_role', label: t('config_field_related_role'), type: 'select', options: availableRoles },
        { name: 'description_en', label: t('config_field_desc_en'), type: 'textarea' },
        { name: 'description_ar', label: t('config_field_desc_ar'), type: 'textarea' },
      ],
      apiAdd: api.addSpecialization, apiUpdate: api.updateSpecialization, apiDelete: api.deleteSpecialization
    },
    lab: {
      label: t('config_catalog_lab'),
      data: labTests,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'category_en', label: t('config_field_category_en'), type: 'text' },
        { name: 'category_ar', label: t('config_field_category_ar'), type: 'text' },
        { name: 'cost', label: t('config_field_cost'), type: 'number', prefix: '$' },
        { name: 'normal_range', label: t('config_field_normal_range'), type: 'text' },
      ],
      apiAdd: api.addLabTest, apiUpdate: api.updateLabTest, apiDelete: api.deleteLabTest
    },
    nurse: {
      label: t('config_catalog_nurse'),
      data: nurseServices,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'description_en', label: t('config_field_desc_en'), type: 'textarea' },
        { name: 'description_ar', label: t('config_field_desc_ar'), type: 'textarea' },
        { name: 'cost', label: t('config_field_cost'), type: 'number', prefix: '$' },
      ],
      apiAdd: api.addNurseService, apiUpdate: api.updateNurseService, apiDelete: api.deleteNurseService
    },
    ops: {
      label: t('config_catalog_ops'),
      data: operations,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'base_cost', label: t('config_field_base_cost'), type: 'number', prefix: '$' },
      ],
      apiAdd: api.addOperationCatalog, apiUpdate: api.updateOperationCatalog, apiDelete: api.deleteOperationCatalog
    },
    insurance: {
      label: t('config_catalog_insurance'),
      data: insuranceProviders,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'is_active', label: t('config_field_status'), type: 'toggle' },
      ],
      apiAdd: api.addInsuranceProvider, apiUpdate: api.updateInsuranceProvider, apiDelete: api.deleteInsuranceProvider
    },
    banks: {
      label: t('config_catalog_banks'),
      data: banks,
      fields: [
        { name: 'name_en', label: t('config_field_name_en'), type: 'text', required: true },
        { name: 'name_ar', label: t('config_field_name_ar'), type: 'text', required: true },
        { name: 'is_active', label: t('config_field_status'), type: 'toggle' },
      ],
      apiAdd: api.addBank, apiUpdate: api.updateBank, apiDelete: api.deleteBank
    }
  };

  const formatPermissionName = (p: string) => {
    return p.replace(/_/g, ' ').toLowerCase();
  };


  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('config_title')}</h1>

      <div className="flex border-b border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 rounded-t-xl px-4 pt-2 overflow-x-auto">
        {[
          { id: 'general', icon: SettingsIcon, label: t('config_tab_general') },
          { id: 'users', icon: Shield, label: t('config_tab_roles') }, 
          { id: 'financial', icon: CreditCard, label: t('config_tab_financial') },
          { id: 'beds', icon: Bed, label: t('config_tab_beds') },
          { id: 'catalogs', icon: Database, label: t('config_tab_catalogs') },
          { id: 'data', icon: Server, label: t('config_tab_data') },
          { id: 'diagnostics', icon: Activity, label: t('config_tab_health') }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)} 
            className={`px-5 py-3 font-medium text-sm border-b-2 transition-all flex items-center gap-2 whitespace-nowrap 
              ${activeTab === tab.id 
                ? 'border-primary-600 text-primary-600 bg-primary-50/50 dark:bg-primary-900/20' 
                : 'border-transparent text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-200 hover:bg-gray-50 dark:hover:bg-slate-700'}`}
          >
            <tab.icon size={18}/> {tab.label}
          </button>
        ))}
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-b-xl shadow-sm border border-t-0 border-gray-200 dark:border-slate-700 p-6 min-h-[400px] relative">
        {loading && <div className="absolute inset-0 z-10 bg-white/80 dark:bg-slate-800/80 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-primary-500" /></div>}

        {!loading && (
          <>
            {activeTab === 'general' && (
              <form onSubmit={handleSaveSettings} className="max-w-xl space-y-6 animate-in fade-in">
                <Input label={t('config_general_hospital_name')} value={settings.hospitalName} onChange={e => setSettings({...settings, hospitalName: e.target.value})} />
                <Input label={t('config_general_address')} value={settings.hospitalAddress} onChange={e => setSettings({...settings, hospitalAddress: e.target.value})} />
                <div className="pt-4 border-t dark:border-slate-700">
                  <Button type="submit" icon={Save}>{t('config_general_save_button')}</Button>
                </div>
              </form>
            )}

            {activeTab === 'users' && (
              <div className="animate-in fade-in">
                <div className="flex gap-2 mb-6">
                   <Button variant={userTabMode === 'accounts' ? 'primary' : 'outline'} onClick={() => setUserTabMode('accounts')} icon={Users}>{t('config_users_accounts_tab')}</Button>
                   <Button variant={userTabMode === 'roles' ? 'primary' : 'outline'} onClick={() => setUserTabMode('roles')} icon={Lock}>{t('config_users_roles_tab')}</Button>
                </div>

                {userTabMode === 'accounts' ? (
                  <>
                    <div className="flex justify-end mb-4"><Button icon={Plus} onClick={() => openUserModal()}>{t('config_users_add_button')}</Button></div>
                    <div className="overflow-x-auto border rounded-xl shadow-sm">
                      <table className="min-w-full divide-y">
                        <thead className="bg-slate-50 dark:bg-slate-900">
                          <tr>
                            <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_users_header_user')}</th>
                            <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_users_header_role')}</th>
                            <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase">{t('config_users_header_status')}</th>
                            <th className="px-4 py-3"></th>
                          </tr>
                        </thead>
                        <tbody className="bg-white divide-y dark:bg-slate-800">
                          {users.map(user => (
                            <tr key={user.id}>
                              <td className="px-4 py-3"><div className="font-medium">{user.fullName}</div><div className="text-xs text-slate-500">{user.username}</div></td>
                              <td className="px-4 py-3 capitalize"><Badge color="blue">{user.role}</Badge></td>
                              <td className="px-4 py-3 text-center"><Badge color={user.isActive ? 'green' : 'gray'}>{user.isActive ? t('config_users_active') : t('config_users_inactive')}</Badge></td>
                              <td className="px-4 py-3 text-right">
                                <button onClick={() => openUserModal(user)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                                <button onClick={() => handleDeleteUser(user.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </>
                ) : (
                  <div className="overflow-x-auto border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                      <thead className="bg-slate-50 dark:bg-slate-900 sticky top-0 z-10">
                        <tr>
                          <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider w-1/4">
                            {t('config_users_feature_column')}
                          </th>
                          {availableRoles.map(role => (
                            <th key={role} className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">
                              <div className="flex flex-col items-center gap-2">
                                <span className="capitalize">{role}</span>
                                {role !== 'admin' && (
                                  <Button size="sm" onClick={() => savePermissions(role)} className="!px-2 !py-0.5 !text-[10px] h-auto">
                                    {t('config_users_permissions_save_button')}
                                  </Button>
                                )}
                              </div>
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody className="bg-white dark:bg-slate-800">
                        {Object.entries(permissionGroups).map(([groupKey, perms]) => (
                          <React.Fragment key={groupKey}>
                            <tr className="bg-slate-50/50 dark:bg-slate-900/50">
                              <td colSpan={availableRoles.length + 1} className="px-4 py-2 text-sm font-bold text-slate-600 dark:text-slate-300">
                                {t(groupKey)}
                              </td>
                            </tr>
                            {perms.map(p => (
                              <tr key={p} className="hover:bg-slate-50 dark:hover:bg-slate-700/30">
                                <td className="px-4 py-3 text-sm font-medium text-slate-700 dark:text-slate-300 capitalize">
                                  {formatPermissionName(p)}
                                </td>
                                {availableRoles.map(role => (
                                  <td key={`${role}-${p}`} className="px-4 py-3 text-center">
                                    <input
                                      type="checkbox"
                                      className="h-5 w-5 rounded text-primary-600 focus:ring-primary-500 disabled:opacity-50 cursor-pointer disabled:cursor-not-allowed"
                                      checked={(rolePermissions[role] || []).includes(p)}
                                      onChange={() => togglePermission(role, p)}
                                      disabled={role === 'admin'}
                                    />
                                  </td>
                                ))}
                              </tr>
                            ))}
                          </React.Fragment>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'financial' && (
              <div className="animate-in fade-in">
                <div className="flex gap-2 mb-6">
                   <Button variant={financeTab === 'tax' ? 'primary' : 'outline'} onClick={() => setFinanceTab('tax')}>{t('config_financial_tax_tab')}</Button>
                   <Button variant={financeTab === 'payment' ? 'primary' : 'outline'} onClick={() => setFinanceTab('payment')}>{t('config_financial_payment_tab')}</Button>
                </div>
                {financeTab === 'tax' ? (
                  <div>
                    <div className="flex justify-end mb-4"><Button size="sm" icon={Plus} onClick={() => openFinanceModal('tax')}>{t('add')}</Button></div>
                    {taxes.map(t => <div key={t.id} className="flex justify-between items-center py-2 border-b last:border-0"><span>{t.name_en} ({t.rate}%)</span><div><button onClick={() => openFinanceModal('tax', t)} className="p-1"><Edit size={14}/></button><button onClick={() => handleDeleteFinance(t.id, 'tax')} className="p-1 text-red-500"><Trash2 size={14}/></button></div></div>)}
                  </div>
                ) : (
                  <div>
                    <div className="flex justify-end mb-4"><Button size="sm" icon={Plus} onClick={() => openFinanceModal('payment')}>{t('add')}</Button></div>
                    {paymentMethods.map(p => <div key={p.id} className="flex justify-between items-center py-2 border-b last:border-0"><span>{p.name_en}</span><div><button onClick={() => openFinanceModal('payment', p)} className="p-1"><Edit size={14}/></button><button onClick={() => handleDeleteFinance(p.id, 'payment')} className="p-1 text-red-500"><Trash2 size={14}/></button></div></div>)}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'beds' && (
              <div className="animate-in fade-in">
                <div className="flex justify-end mb-4"><Button icon={Plus} onClick={() => openBedModal()}>{t('config_beds_add_button')}</Button></div>
                <div className="overflow-x-auto border rounded-xl shadow-sm">
                  <table className="min-w-full divide-y">
                    <thead className="bg-slate-50 dark:bg-slate-900">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_room')}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_type')}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_cost')}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_status')}</th>
                        <th className="px-4 py-3"></th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y dark:bg-slate-800">
                      {beds.map(bed => (
                        <tr key={bed.id}>
                          <td className="px-4 py-3 font-medium">{bed.roomNumber}</td>
                          <td className="px-4 py-3">{bed.type}</td>
                          <td className="px-4 py-3 text-right font-mono">${bed.costPerDay}</td>
                          <td className="px-4 py-3 text-center capitalize"><Badge color={bed.status === 'available' ? 'green' : bed.status === 'cleaning' ? 'purple' : 'red'}>{t(`config_bed_status_${bed.status}`)}</Badge></td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => openBedModal(bed)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                            <button onClick={() => handleDeleteBed(bed.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'catalogs' && (
              <div className="animate-in fade-in">
                <div className="flex flex-col sm:flex-row justify-between gap-4 mb-6">
                  <div className="flex gap-1 bg-gray-100 dark:bg-slate-900 p-1 rounded-xl w-full sm:w-auto overflow-x-auto">
                    {Object.keys(catalogMetadata).map(key => (
                      <button 
                        key={key}
                        onClick={() => setCatalogTab(key as CatalogType)} 
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all shadow-sm whitespace-nowrap ${catalogTab === key ? 'bg-white dark:bg-slate-800 text-primary-700 shadow' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                      >
                        {catalogMetadata[key as CatalogType].label}
                      </button>
                    ))}
                  </div>
                  <Button size="sm" icon={Plus} onClick={() => openItemModal()}>{t('config_catalogs_add_button')}</Button>
                </div>

                <div className="overflow-x-auto border rounded-xl shadow-sm">
                  <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-700">
                    <thead className="bg-gray-50/80 dark:bg-slate-900">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_name_en')}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_name_ar')}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_details')}</th>
                        <th className="px-4 py-3 text-right"></th>
                      </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-gray-200 dark:divide-slate-700">
                      {catalogMetadata[catalogTab].data.map((item: any) => (
                        <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700">
                          <td className="px-4 py-3 text-sm font-medium text-gray-900">{item.name_en}</td>
                          <td className="px-4 py-3 text-sm text-gray-700 dark:text-slate-300">{item.name_ar}</td>
                          <td className="px-4 py-3 text-sm text-right font-mono text-slate-500">
                            {item.cost !== undefined && `$${item.cost}`}
                            {item.base_cost !== undefined && `$${item.base_cost}`}
                            {item.rate !== undefined && `${item.rate}%`}
                            {item.related_role && <span className="mr-2 text-xs bg-gray-100 dark:bg-gray-700 px-1 rounded">{item.related_role}</span>}
                            {item.isActive !== undefined && <Badge color={item.isActive ? 'green' : 'gray'}>{item.isActive ? t('config_users_active') : t('config_users_inactive')}</Badge>}
                          </td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => openItemModal(item)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                            <button onClick={() => handleDeleteItem(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'data' && (
              <div className="max-w-xl space-y-8 animate-in fade-in">
                <Card title={t('config_data_backup_title')} action={<Button icon={Download} onClick={handleDownloadBackup}>{t('config_data_backup_button')}</Button>}>
                  <p>{t('config_data_backup_note')}</p>
                </Card>
                <Card title={t('config_data_restore_title')}>
                  <form onSubmit={handleRestoreDatabase} className="space-y-4">
                    <Input type="file" accept=".db,.sqlite,.sqlite3" onChange={e => setRestoreFile(e.target.files ? e.target.files[0] : null)} />
                    <Button type="submit" icon={Upload} disabled={!restoreFile}>{t('config_data_restore_button')}</Button>
                  </form>
                </Card>
                <Card title={t('config_data_danger_title')} className="border-red-500 bg-red-50 dark:bg-red-900/10">
                  <div className="flex justify-between items-center">
                    <div>
                      <h4 className="font-bold text-red-800 dark:text-red-300">{t('config_data_danger_reset_title')}</h4>
                      <p className="text-sm text-red-600 dark:text-red-400">{t('config_data_danger_reset_note')}</p>
                    </div>
                    <Button variant="danger" icon={RotateCcw} onClick={handleResetDatabase}>{t('config_data_danger_reset_button')}</Button>
                  </div>
                </Card>
              </div>
            )}

            {activeTab === 'diagnostics' && (
              <div className="max-w-3xl space-y-6 animate-in fade-in">
                <Button onClick={runDiagnostics} disabled={isTesting} icon={isTesting ? undefined : RefreshCw}>
                  {isTesting ? <><Loader2 className="w-4 h-4 mr-2 animate-spin"/>{t('config_health_running_button')}</> : t('config_health_run_button')}
                </Button>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                  <DiagnosticStat title={t('config_health_stat_status')} value={healthData?.status || t('none')} icon={healthData?.status === 'operational' ? CheckCircle : AlertTriangle} />
                  <DiagnosticStat title={t('config_health_stat_latency')} value={healthData?.database?.latency || t('none')} icon={Database} />
                  <DiagnosticStat title={t('config_health_stat_uptime')} value={healthData?.uptime ? `${(healthData.uptime / 60).toFixed(1)} mins` : t('none')} icon={Activity} />
                  <DiagnosticStat title={t('config_health_stat_memory')} value={healthData?.memory?.rss || t('none')} icon={Server} />
                </div>

                {testLogs.length > 0 && (
                  <div className="bg-slate-900 text-slate-300 p-4 rounded-xl text-xs font-mono h-64 overflow-y-auto custom-scrollbar">
                    {testLogs.map((log, i) => <p key={i} className={`flex items-start gap-2 ${log.startsWith('❌') ? 'text-red-400' : log.startsWith('✅') ? 'text-green-400' : ''}`}><span className="text-slate-600 select-none">&gt;</span><span className="flex-1">{log}</span></p>)}
                  </div>
                )}
              </div>
            )}

          </>
        )}
      </div>

       {/* CATALOG ITEM MODAL (DYNAMIC) */}
      <Modal 
        isOpen={isItemModalOpen} 
        onClose={() => setIsItemModalOpen(false)} 
        title={`${editingItemId ? t('edit') : t('add')} ${catalogMetadata[catalogTab].label}`}
      >
        <form onSubmit={handleItemSubmit} className="space-y-4">
          {catalogMetadata[catalogTab].fields.map((field: any) => {
            if (field.type === 'textarea') {
              return <Textarea key={field.name} label={field.label} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})} required={field.required} />
            }
            if (field.type === 'select') {
                return (
                    <Select key={field.name} label={field.label} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})}>
                        <option value="">{t('config_field_related_role')}...</option>
                        {field.options.map((opt: string) => <option key={opt} value={opt}>{opt.charAt(0).toUpperCase() + opt.slice(1)}</option>)}
                    </Select>
                )
            }
            if (field.type === 'toggle') {
              return (
                <div key={field.name} className="flex items-center gap-2">
                  <input type="checkbox" id={field.name} checked={itemFormData[field.name] !== false} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.checked})} />
                  <label htmlFor={field.name}>{field.label}</label>
                </div>
              )
            }
            return <Input key={field.name} label={field.label} type={field.type || 'text'} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})} required={field.required} prefix={field.prefix} />
          })}
          <div className="flex justify-end pt-4 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsItemModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{editingItemId ? t('edit') : t('add')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title={editingUserId ? t('edit') : t('add')}>
        <form onSubmit={handleUserSubmit} className="space-y-4">
          <Input label={t('patients_modal_form_fullName')} required value={userForm.fullName || ''} onChange={e => setUserForm({...userForm, fullName: e.target.value})} />
          <Input label={t('settings_profile_username')} required value={userForm.username || ''} onChange={e => setUserForm({...userForm, username: e.target.value})} />
          <Input label={t('login_password_label')} type="password" placeholder={editingUserId ? t('settings_security_new_password') : ''} value={userForm.password || ''} onChange={e => setUserForm({...userForm, password: e.target.value})} required={!editingUserId} />
          <Input label={t('settings_profile_email')} type="email" value={userForm.email || ''} onChange={e => setUserForm({...userForm, email: e.target.value})} />
          <Select label={t('config_users_header_role')} value={userForm.role} onChange={e => setUserForm({...userForm, role: e.target.value})}>
            {availableRoles.map(r => <option key={r} value={r} className="capitalize">{r}</option>)}
          </Select>
          <div className="flex justify-end pt-4 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsUserModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{editingUserId ? t('edit') : t('add')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isBedModalOpen} onClose={() => setIsBedModalOpen(false)} title={editingBedId ? t('edit') : t('add')}>
         <form onSubmit={handleBedSubmit} className="space-y-4">
           <Input label={t('config_beds_header_room')} required value={bedForm.roomNumber || ''} onChange={e => setBedForm({...bedForm, roomNumber: e.target.value})} />
           <Select label={t('config_beds_header_type')} value={bedForm.type} onChange={e => setBedForm({...bedForm, type: e.target.value as any})}>
             <option>General</option><option>Private</option><option>ICU</option>
           </Select>
           <Input label={t('config_beds_header_cost')} type="number" value={bedForm.costPerDay || 0} onChange={e => setBedForm({...bedForm, costPerDay: parseFloat(e.target.value)})} />
           <Select label={t('status')} value={bedForm.status} onChange={e => setBedForm({...bedForm, status: e.target.value as any})}>
             <option value="available">{t('config_bed_status_available')}</option>
             <option value="maintenance">{t('config_bed_status_maintenance')}</option>
             <option value="cleaning">{t('config_bed_status_cleaning')}</option>
             <option value="reserved">{t('config_bed_status_reserved')}</option>
             <option value="occupied">{t('config_bed_status_occupied')}</option>
           </Select>
           <div className="flex justify-end pt-4 gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsBedModalOpen(false)}>{t('cancel')}</Button>
             <Button type="submit">{editingBedId ? t('edit') : t('add')}</Button>
           </div>
         </form>
      </Modal>

      <Modal isOpen={isFinanceModalOpen} onClose={() => setIsFinanceModalOpen(false)} title={`${editingFinanceId ? t('edit') : t('add')} ${financeTab === 'tax' ? t('config_financial_tax_tab') : t('config_financial_payment_tab')}`}>
        <form onSubmit={handleFinanceSubmit} className="space-y-4">
           <Input label={t('config_field_name_en')} required value={financeForm.name_en || ''} onChange={e => setFinanceForm({...financeForm, name_en: e.target.value})} />
           <Input label={t('config_field_name_ar')} required value={financeForm.name_ar || ''} onChange={e => setFinanceForm({...financeForm, name_ar: e.target.value})} />
           {financeTab === 'tax' && (
             <Input label={t('config_field_rate')} type="number" required value={financeForm.rate || ''} onChange={e => setFinanceForm({...financeForm, rate: e.target.value})} />
           )}
           <div className="flex items-center gap-2"><input type="checkbox" checked={financeForm.isActive !== false} onChange={e => setFinanceForm({...financeForm, isActive: e.target.checked})} /> {t('config_users_active')}</div>
           <div className="flex justify-end pt-2 gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsFinanceModalOpen(false)}>{t('cancel')}</Button>
             <Button type="submit">{t('save')}</Button>
           </div>
        </form>
      </Modal>

      {/* --- CONFIRMATION DIALOG --- */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={() => {
          confirmState.action();
          setConfirmState({ ...confirmState, isOpen: false });
        }}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type || 'danger'}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Plus, Search, Briefcase, Clock, 
  Calendar, DollarSign, Wallet,
  Loader2, Edit, Trash2, MapPin,
  LogIn, LogOut, CheckCircle, XCircle
} from 'lucide-react';
import { api } from '../services/api';
import { MedicalStaff, Attendance, LeaveRequest, PayrollRecord, FinancialAdjustment } from '../types';
import { hasPermission, Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';

const DAYS_OF_WEEK_EN = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
const DAYS_OF_WEEK_AR = ['إث', 'ثل', 'أر', 'خم', 'جم', 'سب', 'أح'];

// Extended mapping for Role -> Departments
const roleDepartmentMap: Record<string, string[]> = {
  doctor: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Dermatology', 'Radiology', 'Anesthesiology', 'Internal Medicine'],
  nurse: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Internal Medicine'],
  technician: ['Radiology', 'Laboratory'],
  anesthesiologist: ['Anesthesiology', 'General Surgery'],
  pharmacist: ['Pharmacy'],
  hr_manager: ['Administration', 'HR'],
  accountant: ['Finance', 'Administration'],
  manager: ['Administration', 'Management'],
  staff: ['Administration', 'Maintenance', 'Security', 'Support Services', 'Finance', 'IT Support'],
  medical_assistant: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'General Surgery', 'Internal Medicine'],
  receptionist: ['Administration', 'Front Desk']
};

export const Staff = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'directory' | 'attendance' | 'leaves' | 'payroll' | 'financials'>('directory');
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const { user: currentUser } = useAuth();
  const [loading, setLoading] = useState(true);

  const DAYS_OF_WEEK = language === 'ar' ? DAYS_OF_WEEK_AR : DAYS_OF_WEEK_EN;

  // Tab specific data
  const [attendance, setAttendance] = useState<Attendance[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>([]);
  const [payroll, setPayroll] = useState<PayrollRecord[]>([]);
  const [financials, setFinancials] = useState<FinancialAdjustment[]>([]);

  // Catalogs for dropdowns
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [banks, setBanks] = useState<any[]>([]);

  // UI States
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false); // Staff Add/Edit
  const [isAdjustmentModalOpen, setIsAdjustmentModalOpen] = useState(false); // Fine/Bonus/Loan
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false); // Request Leave
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]); // For attendance
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7)); // For payroll YYYY-MM

  // Advanced Process State
  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  // Confirm State
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  // Forms
  const [staffForm, setStaffForm] = useState<Partial<MedicalStaff & { bankName?: string, bankAccount?: string, address?: string } | any>>({});
  const [adjForm, setAdjForm] = useState({ staffId: '', type: 'bonus', amount: '', reason: '', date: new Date().toISOString().split('T')[0] });
  const [leaveForm, setLeaveForm] = useState({ staffId: '', type: 'sick', startDate: '', endDate: '', reason: '' });

  // New Attendance Modal State
  const [attendanceModal, setAttendanceModal] = useState<{
      isOpen: boolean;
      staffId: number;
      staffName: string;
      status: 'present' | 'late' | 'absent' | 'half_day';
      checkIn: string;
      checkOut: string;
      isUpdate: boolean;
  } | null>(null);

  const loadData = async (isBackground = false) => {
    if (!isBackground) setLoading(true);
    try {
      const [data, depts, specs, bankData] = await Promise.all([
        api.getStaff(),
        api.getDepartments(),
        api.getSpecializations(),
        api.getBanks()
      ]);
      setStaff(Array.isArray(data) ? data : []);
      setDepartments(Array.isArray(depts) ? depts : []);
      setSpecializations(Array.isArray(specs) ? specs : []);
      setBanks(Array.isArray(bankData) ? bankData : []);
    } catch (e) {
      console.error("Failed to load staff data:", e);
    } finally {
      if (!isBackground) setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  useEffect(() => {
    const fetchTabData = async () => {
        if (activeTab === 'attendance') setAttendance(await api.getAttendance(selectedDate));
        else if (activeTab === 'leaves') setLeaves(await api.getLeaves());
        else if (activeTab === 'payroll') setPayroll(await api.getPayroll(selectedMonth));
        else if (activeTab === 'financials') setFinancials(await api.getFinancials('all'));
    };
    if(activeTab !== 'directory') fetchTabData();
  }, [activeTab, selectedDate, selectedMonth]);

  const canManageHR = hasPermission(currentUser, Permissions.MANAGE_HR);

  const handleCreateStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!staffForm.fullName) return;

    setProcessStatus('processing');
    setProcessMessage(staffForm.id ? t('staff_updating') : t('staff_creating'));

    const { bankName, bankAccount, ...restOfForm } = staffForm;

    // Ensure numbers are converted, empty string becomes 0
    const payload = {
        ...restOfForm,
        address: restOfForm.address || null,
        baseSalary: parseFloat(restOfForm.baseSalary) || 0,
        consultationFee: parseFloat(restOfForm.consultationFee) || 0,
        consultationFeeFollowup: parseFloat(restOfForm.consultationFeeFollowup) || 0,
        consultationFeeEmergency: parseFloat(restOfForm.consultationFeeEmergency) || 0,
        bankDetails: { bankName, bankAccount }
    };

    try {
      if (staffForm.id) await api.updateStaff(staffForm.id, payload);
      else await api.addStaff(payload);

      setProcessStatus('success');
      setProcessMessage(staffForm.id ? t('staff_update_success') : t('staff_create_success'));

      await loadData(true);

      setTimeout(() => {
        setIsModalOpen(false);
        setProcessStatus('idle');
      }, 500);

    } catch (err: any) {
      setProcessStatus('error');
      setProcessMessage(err.response?.data?.error || t('staff_save_fail'));
    }
  };

  const openStaffModal = (s?: MedicalStaff) => {
      let bankDetailsParsed = { bankName: '', bankAccount: '' };
      if (s?.bankDetails) {
          if (typeof s.bankDetails === 'object' && s.bankDetails !== null) {
              bankDetailsParsed = { bankName: s.bankDetails.bankName, bankAccount: s.bankDetails.bankAccount };
          } else if (typeof s.bankDetails === 'string') {
              bankDetailsParsed = { bankName: s.bankDetails, bankAccount: '' };
          }
      }

      const formState = s ? { 
          ...s, 
          address: s.address || '',
          ...bankDetailsParsed,
      } : { 
          fullName: '', type: 'doctor', status: 'active', 
          baseSalary: '', 
          availableDays: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'],
          availableTimeStart: '09:00', availableTimeEnd: '17:00',
          consultationFee: '', consultationFeeFollowup: '', consultationFeeEmergency: '',
          joinDate: new Date().toISOString().split('T')[0],
          address: '',
          ...bankDetailsParsed
      };

      setStaffForm(formState);
      setIsModalOpen(true);
  };

  const toggleDay = (day: string) => {
      const currentDays = staffForm.availableDays || [];
      const dayEN = DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)];
      if (currentDays.includes(dayEN)) {
          setStaffForm({ ...staffForm, availableDays: currentDays.filter((d: string) => d !== dayEN) });
      } else {
          setStaffForm({ ...staffForm, availableDays: [...currentDays, dayEN] });
      }
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value;
    setStaffForm(prev => ({
        ...prev,
        type: newType as any,
        department: '',
        specialization: ''
    }));
  };

  const filteredDepartments = useMemo(() => {
    if (!staffForm.type) return departments;
    const allowedDepts = roleDepartmentMap[staffForm.type];
    if (!allowedDepts || allowedDepts.length === 0) return departments;
    return departments.filter(d => allowedDepts.includes(d.name_en));
  }, [staffForm.type, departments]);

  const filteredSpecializations = useMemo(() => {
    if (!staffForm.type) return specializations;
    return specializations.filter(s => !s.related_role || s.related_role === staffForm.type);
  }, [staffForm.type, specializations]);

  // --- Attendance Actions ---

  const handleCheckIn = (staffMember: MedicalStaff) => {
    setConfirmState({
        isOpen: true,
        title: t('staff_attendance_confirm'),
        message: t('staff_attendance_checkin_confirm', {name: staffMember.fullName, time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}),
        action: async () => {
            setProcessStatus('processing');
            setProcessMessage(t('processing'));
            try {
                const now = new Date();
                const timeString = now.toTimeString().slice(0, 5);
                let status: 'present' | 'late' = 'present';
                if (staffMember.availableTimeStart && timeString > staffMember.availableTimeStart) {
                    status = 'late';
                }

                await api.markAttendance({
                    staffId: staffMember.id,
                    date: selectedDate,
                    status: status,
                    checkIn: timeString
                });
                const data = await api.getAttendance(selectedDate);
                setAttendance(data);
                setProcessStatus('success');
                setProcessMessage(t('success'));
                setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) {
                setProcessStatus('error');
                setProcessMessage(e.message || t('staff_attendance_mark_fail'));
            }
        }
    });
  };

  const handleCheckOut = (record: Attendance) => {
    setConfirmState({
        isOpen: true,
        title: t('staff_attendance_confirm'),
        message: t('staff_attendance_checkout_confirm', {name: record.staffName}),
        action: async () => {
            setProcessStatus('processing');
            setProcessMessage(t('processing'));
            try {
                const now = new Date();
                const timeString = now.toTimeString().slice(0, 5);
                await api.markAttendance({
                    staffId: record.staffId,
                    date: record.date,
                    status: record.status,
                    checkOut: timeString
                });
                const data = await api.getAttendance(selectedDate);
                setAttendance(data);
                setProcessStatus('success');
                setProcessMessage(t('success'));
                setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) {
                setProcessStatus('error');
                setProcessMessage(e.message || t('staff_attendance_mark_fail'));
            }
        }
    });
  };

  const openAttendanceModal = (staffId: number, staffName: string, status: 'present' | 'late' | 'absent' | 'half_day') => {
      const existingRecord = attendance.find(a => a.staffId === staffId);
      const now = new Date();
      const timeString = now.toTimeString().slice(0, 5);

      setAttendanceModal({
          isOpen: true,
          staffId,
          staffName,
          status: existingRecord ? existingRecord.status : status,
          checkIn: existingRecord?.checkIn || (status !== 'absent' ? timeString : ''),
          checkOut: existingRecord?.checkOut || '',
          isUpdate: !!existingRecord
      });
  };

  const handleAttendanceSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!attendanceModal) return;

      setProcessStatus('processing');
      setProcessMessage(t('processing'));

      try {
          await api.markAttendance({
              staffId: attendanceModal.staffId, 
              date: selectedDate, 
              status: attendanceModal.status,
              checkIn: ['present', 'late', 'half_day'].includes(attendanceModal.status) ? attendanceModal.checkIn : null,
              checkOut: ['present', 'late', 'half_day'].includes(attendanceModal.status) && attendanceModal.checkOut ? attendanceModal.checkOut : null
          });
          const data = await api.getAttendance(selectedDate);
          setAttendance(data);

          setProcessStatus('success');
          setProcessMessage(t('success'));
          setTimeout(() => {
              setProcessStatus('idle');
              setAttendanceModal(null);
          }, 500);
      } catch (err: any) {
          setProcessStatus('error');
          setProcessMessage(err.message || t('staff_attendance_mark_fail'));
      }
  };

  const handleLeaveRequest = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      setProcessMessage(t('processing'));
      try {
        await api.requestLeave(leaveForm);
        const data = await api.getLeaves();
        setLeaves(data);
        setProcessStatus('success');
        setProcessMessage(t('success'));
        setTimeout(() => {
            setIsLeaveModalOpen(false);
            setProcessStatus('idle');
        }, 1000);
      } catch (e: any) {
        setProcessStatus('error');
        setProcessMessage(e.message || 'Failed to request leave');
      }
  };

  const updateLeaveStatus = (id: number, status: string) => {
      setConfirmState({
        isOpen: true,
        title: status === 'approved' ? t('hr_approve') : t('hr_reject'),
        message: t('confirm'),
        action: async () => {
            setProcessStatus('processing');
            setProcessMessage(t('processing'));
            try {
                await api.updateLeaveStatus(id, status);
                const data = await api.getLeaves();
                setLeaves(data);
                setProcessStatus('success');
                setProcessMessage(t('success'));
                setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) {
                setProcessStatus('error');
                setProcessMessage(e.message || 'Failed to update leave status');
            }
        }
      });
  };

  const handleGeneratePayroll = () => {
      setConfirmState({
          isOpen: true,
          title: t('staff_tab_payroll'),
          message: t('staff_generate_payroll_confirm', {month: selectedMonth}),
          action: async () => {
              setProcessStatus('processing');
              setProcessMessage(t('processing'));
              try {
                  await api.generatePayroll({ month: selectedMonth });
                  const data = await api.getPayroll(selectedMonth);
                  setPayroll(data);
                  setProcessStatus('success');
                  setProcessMessage(t('success'));
                  setTimeout(() => setProcessStatus('idle'), 1000);
              } catch(e: any) {
                  setProcessStatus('error');
                  setProcessMessage(e.message || 'Failed to generate payroll');
              }
          }
      });
  };

  const handleMarkPaid = (record: PayrollRecord) => {
      setConfirmState({
          isOpen: true,
          title: t('confirm'),
          message: t('staff_payroll_paid_confirm', {name: record.staffName}),
          action: async () => {
              setProcessStatus('processing');
              setProcessMessage(t('processing'));
              try {
                  await api.updatePayrollStatus(record.id, 'paid');
                  const data = await api.getPayroll(selectedMonth);
                  setPayroll(data);
                  setProcessStatus('success');
                  setProcessMessage(t('success'));
                  setTimeout(() => setProcessStatus('idle'), 1000);
              } catch(e: any) {
                  setProcessStatus('error');
                  setProcessMessage(e.message || 'Failed to update status');
              }
          }
      });
  };

  const handleAdjustmentSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      setProcessMessage(t('processing'));
      try {
        await api.addAdjustment({ ...adjForm, amount: parseFloat(adjForm.amount) });
        const data = await api.getFinancials('all');
        setFinancials(data);
        setProcessStatus('success');
        setProcessMessage(t('success'));
        setTimeout(() => {
            setIsAdjustmentModalOpen(false);
            setProcessStatus('idle');
        }, 1000);
      } catch (e: any) {
        setProcessStatus('error');
        setProcessMessage(e.message || 'Failed to add entry');
      }
  };

  const statusOrder: { [key in MedicalStaff['status']]: number } = {
    active: 1,
    inactive: 2,
    dismissed: 3,
  };

  const sortedStaff = staff
    .filter(s => s.fullName.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => (statusOrder[a.status] || 99) - (statusOrder[b.status] || 99));

  return (
    <div className="space-y-6">
      {/* Loading & Status Overlay */}
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 relative overflow-hidden text-center transform scale-100 animate-in zoom-in-95 border dark:border-slate-700">
            {processStatus === 'processing' && (
              <>
                <div className="relative mb-6">
                   <div className="w-16 h-16 border-4 border-slate-100 dark:border-slate-800 border-t-primary-600 rounded-full animate-spin"></div>
                   <Loader2 className="absolute inset-0 m-auto text-primary-600 animate-pulse" size={24}/>
                </div>
                <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">{t('processing')}</h3>
                <p className="text-slate-500 dark:text-slate-400">{processMessage}</p>
              </>
            )}
            {processStatus === 'success' && (
              <>
                <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mb-6 text-green-600 dark:text-green-400 animate-in zoom-in duration-300">
                  <CheckCircle size={40} strokeWidth={3} />
                </div>
                <h3 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">{t('success')}</h3>
                <p className="text-slate-600 dark:text-slate-300 font-medium">{processMessage}</p>
              </>
            )}
            {processStatus === 'error' && (
              <>
                <div className="w-20 h-20 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-6 text-red-600 dark:text-red-400 animate-in zoom-in duration-300">
                  <XCircle size={40} strokeWidth={3} />
                </div>
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{t('patients_process_title_failed')}</h3>
                <p className="text-red-600 bg-red-50 dark:bg-red-900/20 p-3 rounded-xl border border-red-100 dark:border-red-900/50 text-sm mb-6 w-full">{processMessage}</p>
                <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>
              </>
            )}
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('staff_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('staff_subtitle')}</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-x-auto">
          {[
              { id: 'directory', label: t('staff_tab_directory'), icon: Briefcase },
              { id: 'attendance', label: t('staff_tab_attendance'), icon: Clock },
              { id: 'leaves', label: t('staff_tab_leaves'), icon: Calendar },
              { id: 'payroll', label: t('staff_tab_payroll'), icon: DollarSign },
              { id: 'financials', label: t('staff_tab_financials'), icon: Wallet },
          ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                  <tab.icon size={16} /> {tab.label}
              </button>
          ))}
      </div>

      {/* --- DIRECTORY TAB --- */}
      {activeTab === 'directory' && (
          <div className="animate-in fade-in">
              <div className="flex justify-between mb-4">
                  <div className="relative w-72">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                      <input 
                        type="text" 
                        placeholder={t('staff_search_placeholder')} 
                        className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500"
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                      />
                  </div>
                  {canManageHR && <Button onClick={() => openStaffModal()} icon={Plus}>{t('staff_add_employee_button')}</Button>}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                  {sortedStaff.map(person => (
                      <div key={person.id} className="bg-white dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm hover:shadow-md transition-all group">
                          <div className="flex justify-between items-start mb-4">
                              <div className="flex items-center gap-3">
                                  <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg text-white bg-gradient-to-br from-slate-400 to-slate-500`}>
                                      {person.fullName.charAt(0)}
                                  </div>
                                  <div>
                                      <h3 className="font-bold text-slate-800 dark:text-white line-clamp-1">{person.fullName}</h3>
                                      <Badge color="blue">{t(`staff_role_${person.type}`)}</Badge>
                                  </div>
                              </div>
                              <div className={`w-2 h-2 rounded-full ${person.status === 'active' ? 'bg-green-500' : 'bg-gray-300'}`}></div>
                          </div>

                          <div className="space-y-2 text-sm text-slate-500 dark:text-slate-400 mb-4">
                              <div className="flex items-center gap-2"><Briefcase size={14}/> {person.department || t('patients_modal_view_na')}</div>
                              <div className="flex items-center gap-2"><MapPin size={14}/> {person.phone || t('patients_modal_view_na')}</div>
                              <div className="flex items-center gap-2 truncate"><MapPin size={14}/> {person.email || t('patients_modal_view_na')}</div>
                              {person.address && <div className="flex items-center gap-2 truncate"><MapPin size={14}/> {person.address}</div>}
                          </div>

                          {canManageHR && (
                              <Button variant="outline" className="w-full" onClick={() => openStaffModal(person)}>
                                  {t('edit')}
                              </Button>
                          )}
                      </div>
                  ))}
              </div>
          </div>
      )}

      {/* --- ATTENDANCE TAB --- */}
      {activeTab === 'attendance' && (
          <div className="animate-in fade-in">
              <div className="flex justify-end mb-4">
                  <Input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} className="w-auto" />
              </div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-medium">
                          <tr>
                              <th className="px-4 py-3">{t('staff_form_role_title')}</th>
                              <th className="px-4 py-3">{t('status')}</th>
                              <th className="px-4 py-3">{t('staff_attendance_time')}</th>
                              <th className="px-4 py-3">Check Out</th>
                              {canManageHR && <th className="px-4 py-3 text-right">{t('actions')}</th>}
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                          {staff.filter(s => s.status === 'active').map(s => {
