import React, { useState, useEffect } from 'react';
import { Card, Button, Badge, Modal, Input, Textarea } from '../components/UI';
import { FlaskConical, CheckCircle, Search, Clock, FileText, User, ChevronRight, Activity, History as HistoryIcon, Save } from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';

export const Laboratory = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<'queue' | 'history'>('queue');
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal State
  const [isProcessModalOpen, setIsProcessModalOpen] = useState(false);
  const [selectedReq, setSelectedReq] = useState<any>(null);
  const [resultForm, setResultForm] = useState({ notes: '', results: '' });
  const [processStatus, setProcessStatus] = useState('idle');

  const loadData = async () => {
    setLoading(true);
    try {
      // In a real app, you might have separate endpoints. 
      // For now, we fetch all and filter client-side or assume the endpoint returns relevant data.
      const data = await api.getPendingLabRequests(); 
      // Note: The backend update below will ensure this endpoint or a new one returns both pending and history based on query, 
      // or we just fetch all and filter here if the dataset is small.
      // Let's assume the API returns a unified list we can filter.
      setRequests(Array.isArray(data) ? data : []);
    } catch (e) { console.error(e); } 
    finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  const openProcessModal = (req: any) => {
    setSelectedReq(req);
    setResultForm({ notes: '', results: '' });
    setIsProcessModalOpen(true);
  };

  const handleComplete = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedReq) return;

    setProcessStatus('processing');
    try {
      await api.completeLabRequest(selectedReq.id, resultForm);
      setProcessStatus('success');
      await loadData();
      setTimeout(() => {
        setIsProcessModalOpen(false);
        setProcessStatus('idle');
      }, 1000);
    } catch (error) {
      console.error(error);
      alert(t('lab_save_error'));
      setProcessStatus('idle');
    }
  };

  // Parsing test names from IDs or string (Backend logic dependency)
  // Assuming the backend returns a 'tests' array or string description now.
  // If not, we fall back to generic display.

  const filteredRequests = requests.filter(r => {
    const matchesSearch = r.patientName?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesTab = activeTab === 'queue' 
      ? (r.status === 'pending' || r.status === 'confirmed') 
      : (r.status === 'completed');
    return matchesSearch && matchesTab;
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('lab_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('lab_subtitle')}</p>
        </div>

        <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-lg">
            <button 
                onClick={() => setActiveTab('queue')}
                className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeTab === 'queue' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
            >
                <FlaskConical size={16}/> {t('lab_tab_queue')} <span className="bg-orange-100 text-orange-700 dark:bg-orange-900 dark:text-orange-300 text-xs px-2 py-0.5 rounded-full ml-1">{requests.filter(r => r.status !== 'completed').length}</span>
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeTab === 'history' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
            >
                <HistoryIcon size={16}/> {t('lab_tab_history')}
            </button>
        </div>
      </div>

      {/* Search Toolbar */}
      <Card className="!p-4">
        <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
            <input 
                type="text" 
                placeholder={t('lab_search_placeholder')} 
                className="pl-10 w-full sm:w-96 rounded-lg border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 py-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none transition-all"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
            />
        </div>
      </Card>

      {/* Main Content */}
      <div className="grid grid-cols-1 gap-4">
        {loading ? (
            <div className="text-center py-20 text-slate-400">{t('lab_loading')}</div>
        ) : filteredRequests.length === 0 ? (
            <div className="text-center py-20 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl">
                <FlaskConical size={48} className="mx-auto mb-4 text-slate-300 dark:text-slate-600" />
                <p className="text-slate-500 dark:text-slate-400 font-medium">{t('lab_empty', {tab: activeTab === 'queue' ? t('lab_tab_queue') : t('lab_tab_history')})}</p>
            </div>
        ) : (
            filteredRequests.map(req => (
                <div key={req.id} className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all flex flex-col sm:flex-row gap-6 items-start sm:items-center group">

                    {/* Date/Time Box */}
                    <div className="flex flex-col items-center justify-center p-3 bg-slate-50 dark:bg-slate-900 rounded-lg min-w-[80px] border border-slate-100 dark:border-slate-700">
                        <span className="text-xs font-bold text-slate-400 uppercase">{new Date(req.created_at).toLocaleString('default', { month: 'short' })}</span>
                        <span className="text-xl font-bold text-slate-800 dark:text-slate-200">{new Date(req.created_at).getDate()}</span>
                        <span className="text-xs text-slate-400">{new Date(req.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                    </div>

                    {/* Patient & Test Info */}
                    <div className="flex-1">
                        <div className="flex items-center gap-3 mb-1">
                            <h3 className="text-lg font-bold text-slate-800 dark:text-white">{req.patientName}</h3>
                            {req.status === 'completed' 
                                ? <Badge color="green"><CheckCircle size={12} className="inline mr-1"/>{t('lab_card_results_ready')}</Badge>
                                : req.status === 'confirmed'
                                  ? <Badge color="blue">{t('lab_card_paid')}</Badge>
                                  : <Badge color="yellow">{t('lab_card_payment_pending')}</Badge>
                            }
                        </div>
                        <p className="text-sm text-slate-500 dark:text-slate-400">{req.testNames || 'Multiple Tests'}</p>
                        <p className="text-xs text-slate-400 font-mono mt-2">ID: {req.id}</p>
                    </div>

                    {/* Cost */}
                    <div className="text-right">
                        <span className="text-xs text-slate-400">{t('config_field_cost')}</span>
                        <p className="text-xl font-bold text-slate-800 dark:text-white">${req.projected_cost.toLocaleString()}</p>
                    </div>

                    {/* Actions */}
                    <div className="sm:ml-auto">
                        {req.status === 'confirmed' && (
                            <Button onClick={() => openProcessModal(req)} icon={Activity} className="bg-gradient-to-r from-primary-600 to-indigo-600 shadow-lg shadow-primary-500/20">
                                {t('lab_card_enter_results')}
                            </Button>
                        )}
                        {req.status === 'pending' && (
                            <div className="text-sm text-orange-600 font-medium flex items-center gap-2 bg-orange-50 dark:bg-orange-900/20 p-3 rounded-lg border border-orange-100 dark:border-orange-800">
                                <Clock size={16}/>
                                <span>{t('lab_card_awaiting_payment')}</span>
                            </div>
                        )}
                        {req.status === 'completed' && (
                            <Button variant="secondary" icon={FileText} onClick={() => openProcessModal(req)}>
                                {t('lab_view_results')}
                            </Button>
                        )}
                    </div>
                </div>
            ))
        )}
      </div>

      {/* Process Modal */}
      <Modal isOpen={isProcessModalOpen} onClose={() => setIsProcessModalOpen(false)} title={`${t('lab_modal_title')} - ${selectedReq?.patientName}`}>
        <form onSubmit={handleComplete} className="space-y-4">
          <div>
            <h4 className="font-bold mb-2">{selectedReq?.testNames}</h4>
            <Textarea 
              label={t('lab_modal_findings')}
              placeholder={t('lab_modal_findings_placeholder')}
              rows={6}
              value={resultForm.results}
              onChange={e => setResultForm({...resultForm, results: e.target.value})}
              required={selectedReq?.status !== 'completed'}
              disabled={selectedReq?.status === 'completed'}
            />
          </div>
          <Textarea 
            label={t('lab_modal_notes')}
            placeholder={t('lab_modal_notes_placeholder')}
            rows={2}
            value={resultForm.notes}
            onChange={e => setResultForm({...resultForm, notes: e.target.value})}
            disabled={selectedReq?.status === 'completed'}
          />
          <div className="pt-4 flex justify-end gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsProcessModalOpen(false)}>{t('close')}</Button>
            {selectedReq?.status !== 'completed' && (
              <Button type="submit" icon={Save} disabled={processStatus === 'processing'}>
                {processStatus === 'processing' ? t('processing') : t('lab_modal_save_button')}
              </Button>
            )}
          </div>
        </form>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Button, Badge, Modal, Input, Select, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Activity, CheckCircle, Clock, User, Syringe, Plus, Trash2, 
  Calculator, Save, ChevronRight, AlertTriangle, Stethoscope, 
  Package, Zap, Calendar, DollarSign, ChevronDown, ChevronUp, FileText, Briefcase, Search, History, Filter
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';

// Configuration Constants
const FEE_RATIOS: Record<string, number> = {
  'anesthesiologist': 0.5,
  'assistant': 0.5,
  'nurse': 0.33,
  'technician': 0.25
};

export const Operations = () => {
  const { t } = useTranslation();
  const [ops, setOps] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [staff, setStaff] = useState<any[]>([]);
  const [activeTab, setActiveTab] = useState<'requests' | 'schedule' | 'history'>('requests');
  const [searchTerm, setSearchTerm] = useState('');

  // Estimation Modal State
  const [isEstimateModalOpen, setIsEstimateModalOpen] = useState(false);
  const [selectedOp, setSelectedOp] = useState<any>(null);
  const [expandedSection, setExpandedSection] = useState<string>('team');

  // Confirmation Dialog State
  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    action: () => void;
  }>({ isOpen: false, title: '', message: '', action: () => {} });

  // Revised Cost Form State
  interface Participant {
    id: number;
    role: string;
    staffId: string;
    name: string;
    fee: number;
  }

  interface ResourceItem {
    id: number;
    name: string;
    cost: number;
  }

  const [costForm, setCostForm] = useState({
    surgeonFee: 0,
    theaterFee: 0,
    participants: [] as Participant[],
    consumables: [] as ResourceItem[],
    equipment: [] as ResourceItem[],
    others: [] as ResourceItem[],
  });

  const [processStatus, setProcessStatus] = useState('idle');

  const loadData = async () => {
    setLoading(true);
    try {
      const [opsData, staffData] = await Promise.all([
        api.getScheduledOperations(),
        api.getStaff()
      ]);
      setOps(opsData);
      setStaff(staffData);
    } catch (e) { console.error(e); } 
    finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  const openEstimateModal = (op: any) => {
    // Determine default fee from the assigned doctor if available
    let initialSurgeonFee = 0;
    if (op.doctor_id) {
        const doctor = staff.find(s => s.id === op.doctor_id);
        if (doctor) initialSurgeonFee = doctor.consultationFee * 5; // Simplified default multiplier
    }

    setCostForm({
      surgeonFee: initialSurgeonFee,
      theaterFee: initialSurgeonFee,
      participants: [],
      consumables: [],
      equipment: [],
      others: [],
    });

    setSelectedOp(op);
    setIsEstimateModalOpen(true);
  };

  // --- LOGIC HANDLERS ---

  const calculateParticipantFee = (role: string, baseSurgeonFee: number) => {
    const ratio = FEE_RATIOS[role] || 0;
    return Math.round(baseSurgeonFee * ratio);
  };

  const handleSurgeonFeeChange = (val: string) => {
    const newFee = parseFloat(val) || 0;
    setCostForm(prev => ({
      ...prev,
      surgeonFee: newFee,
      theaterFee: newFee, 
      participants: prev.participants.map(p => ({
        ...p,
        fee: calculateParticipantFee(p.role, newFee)
      }))
    }));
  };

  const addParticipant = () => {
    setCostForm(prev => ({
      ...prev,
      participants: [...prev.participants, { 
        id: Date.now(), 
        role: 'nurse', 
        staffId: '', 
        name: '', 
        fee: calculateParticipantFee('nurse', prev.surgeonFee) 
      }]
    }));
  };

  const updateParticipant = (index: number, field: keyof Participant, value: any) => {
    setCostForm(prev => {
      const updatedList = [...prev.participants];
      const item = { ...updatedList[index] };

      if (field === 'role') {
        item.role = value;
        item.fee = calculateParticipantFee(value, prev.surgeonFee);
        item.staffId = '';
        item.name = '';
      } else if (field === 'staffId') {
        item.staffId = value;
        const staffMember = staff.find(s => s.id.toString() === value);
        item.name = staffMember?.fullName || '';
      } else if (field === 'fee') {
        item.fee = parseFloat(value) || 0;
      }

      updatedList[index] = item;
      return { ...prev, participants: updatedList };
    });
  };

  const removeParticipant = (index: number) => {
    setCostForm(prev => ({
      ...prev,
      participants: prev.participants.filter((_, i) => i !== index)
    }));
  };

  const addResource = (type: 'consumables' | 'equipment' | 'others') => {
    setCostForm(prev => ({
      ...prev,
      [type]: [...prev[type], { id: Date.now(), name: '', cost: 0 }]
    }));
  };

  const updateResource = (type: 'consumables' | 'equipment' | 'others', index: number, field: 'name' | 'cost', value: any) => {
    setCostForm(prev => {
      const updatedList = [...prev[type]];
      updatedList[index] = { 
        ...updatedList[index], 
        [field]: field === 'cost' ? (parseFloat(value) || 0) : value 
      };
      return { ...prev, [type]: updatedList };
    });
  };

  const removeResource = (type: 'consumables' | 'equipment' | 'others', index: number) => {
    setCostForm(prev => ({
      ...prev,
      [type]: prev[type].filter((_, i) => i !== index)
    }));
  };

  const calculateTotal = () => {
    const participantsTotal = costForm.participants.reduce((sum, p) => sum + p.fee, 0);
    const consumablesTotal = costForm.consumables.reduce((sum, i) => sum + i.cost, 0);
    const equipmentTotal = costForm.equipment.reduce((sum, i) => sum + i.cost, 0);
    const othersTotal = costForm.others.reduce((sum, i) => sum + i.cost, 0);
    return costForm.surgeonFee + costForm.theaterFee + participantsTotal + consumablesTotal + equipmentTotal + othersTotal;
  };

  const handleProcessSubmit = async () => {
    if (!selectedOp) return;
    setProcessStatus('processing');
    try {
      const total = calculateTotal();
      const payload = {
        details: {
          ...costForm,
          anesthesiologist: costForm.participants.find(p => p.role === 'anesthesiologist'),
          assistant: costForm.participants.find(p => p.role === 'assistant'),
        },
        totalCost: total
      };

      await api.processOperationRequest(selectedOp.id, payload);
      setProcessStatus('success');
      setIsEstimateModalOpen(false);
      loadData();
    } catch (e) {
      console.error(e);
      alert("Failed to process request");
    } finally {
      setProcessStatus('idle');
    }
  };

  const handleCompleteOp = (opId: number) => {
    setConfirmState({
      isOpen: true,
      title: t('operations_dialog_complete_title'),
      message: t('operations_dialog_complete_message'),
      action: async () => {
        try {
          await api.completeOperation(opId);
          loadData();
        } catch (e) { 
          console.error(e);
          alert("Failed to update status");
        }
      }
    });
  };

  // Filter lists based on Search & Status
  const filteredOps = ops.filter(op => {
      const search = searchTerm.toLowerCase();
      return (
          op.patientName.toLowerCase().includes(search) ||
          op.operation_name.toLowerCase().includes(search) ||
          (op.doctorName && op.doctorName.toLowerCase().includes(search))
      );
  });

  const pendingRequests = filteredOps.filter(op => op.status === 'requested' || op.status === 'pending_payment');
  const scheduledOps = filteredOps.filter(op => op.status === 'confirmed');
  const completedOps = filteredOps.filter(op => op.status === 'completed');

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('operations_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('operations_subtitle')}</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 w-full lg:w-auto">
            {/* Search Bar */}
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input 
                    type="text" 
                    placeholder={t('operations_search_placeholder')}
                    className="pl-9 pr-4 py-2 w-full sm:w-64 rounded-lg border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none transition-all shadow-sm"
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                />
            </div>

            {/* Tabs */}
            <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-lg shrink-0 overflow-x-auto">
                <button 
                    onClick={() => setActiveTab('requests')}
                    className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'requests' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                >
                    <FileText size={16}/> {t('operations_tab_requests')} <span className="bg-primary-100 dark:bg-primary-900 text-primary-700 dark:text-primary-300 text-xs px-2 py-0.5 rounded-full ml-1">{pendingRequests.length}</span>
                </button>
                <button 
                    onClick={() => setActiveTab('schedule')}
                    className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'schedule' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                >
                    <Calendar size={16}/> {t('operations_tab_schedule')} <span className="bg-green-100 dark:bg-green-900 text-green-700 dark:text-green-300 text-xs px-2 py-0.5 rounded-full ml-1">{scheduledOps.length}</span>
                </button>
                <button 
                    onClick={() => setActiveTab('history')}
                    className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'history' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                >
                    <History size={16}/> {t('operations_tab_history')}
                </button>
            </div>
        </div>
      </div>

      {activeTab === 'requests' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in">
            {pendingRequests.length === 0 ? (
                <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl">
                    <CheckCircle size={48} className="mx-auto mb-3 opacity-20"/>
                    <p>{searchTerm ? t('operations_requests_empty_searched') : t('operations_requests_empty')}</p>
                </div>
            ) : (
                pendingRequests.map(op => (
                    <Card key={op.id} className="relative group border-l-4 border-l-yellow-400">
                        <div className="flex justify-between items-start mb-3">
                            <Badge color={op.status === 'pending_payment' ? 'blue' : 'yellow'}>
                                {op.status === 'pending_payment' ? t('operations_card_awaiting_payment') : t('operations_card_needs_estimation')}
                            </Badge>
                            <span className="text-xs text-slate-400">{new Date(op.created_at).toLocaleDateString()}</span>
                        </div>
                        <h3 className="font-bold text-lg text-slate-800 dark:text-white mb-1">{op.operation_name}</h3>
                        <p className="text-sm text-slate-500 mb-4">{op.patientName} • Dr. {op.doctorName}</p>

                        {op.status === 'pending_payment' ? (
                            <div className="bg-slate-50 dark:bg-slate-900 p-3 rounded-lg flex justify-between items-center">
                                <span className="text-sm font-medium text-slate-600 dark:text-slate-400">{t('operations_card_est_cost')}</span>
                                <span className="font-bold text-lg text-slate-900 dark:text-white">${op.projected_cost.toLocaleString()}</span>
                            </div>
                        ) : (
                            <Button className="w-full" onClick={() => openEstimateModal(op)} icon={Calculator}>
                                {t('operations_card_process_button')}
                            </Button>
                        )}
                    </Card>
                ))
            )}
        </div>
      )}

      {activeTab === 'schedule' && (
          <Card className="!p-0 overflow-hidden animate-in fade-in">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-700">
                <thead className="bg-slate-50 dark:bg-slate-900">
                  <tr>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_status')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_datetime')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_procedure')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_patient')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_surgeon')}</th>
                    <th className="px-6 py-4 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_actions')}</th>
                  </tr>
                </thead>
                <tbody className="bg-white dark:bg-slate-800 divide-y divide-gray-200 dark:divide-slate-700">
                  {scheduledOps.length === 0 ? (
                    <tr><td colSpan={6} className="text-center py-12 text-slate-500">{t('operations_schedule_empty')}</td></tr>
                  ) : (
                    scheduledOps.map(op => (
                      <tr key={op.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap">
                            <Badge color="green">{t('operations_schedule_status_confirmed')}</Badge>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                          {new Date(op.created_at).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-bold text-gray-900 dark:text-white">{op.operation_name}</div>
                        </td>
                        <td className="px-6 py-4 text-sm font-medium text-gray-900 dark:text-white">
                          {op.patientName}
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-600 dark:text-gray-300">
                          Dr. {op.doctorName}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm">
                          <Button size="sm" variant="outline" icon={CheckCircle} onClick={() => handleCompleteOp(op.id)}>
                             {t('operations_schedule_action_complete')}
                          </Button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </Card>
      )}

      {activeTab === 'history' && (
          <Card className="!p-0 overflow-hidden animate-in fade-in">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-700">
                <thead className="bg-slate-50 dark:bg-slate-900">
                  <tr>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_history_header_date')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_procedure')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_patient')}</th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_surgeon')}</th>
                    <th className="px-6 py-4 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_history_header_cost')}</th>
                    <th className="px-6 py-4 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">{t('operations_schedule_header_status')}</th>
                  </tr>
                </thead>
                <tbody className="bg-white dark:bg-slate-800 divide-y divide-gray-200 dark:divide-slate-700">
                  {completedOps.length === 0 ? (
                    <tr><td colSpan={6} className="text-center py-12 text-slate-500">{t('operations_history_empty')}</td></tr>
                  ) : (
                    completedOps.map(op => (
                      <tr key={op.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors opacity-75 hover:opacity-100">
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                          {new Date(op.created_at).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-bold text-gray-900 dark:text-white">{op.operation_name}</div>
                        </td>
                        <td className="px-6 py-4 text-sm font-medium text-gray-900 dark:text-white">
                          {op.patientName}
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-600 dark:text-gray-300">
                          Dr. {op.doctorName}
                        </td>
                        <td className="px-6 py-4 text-right text-sm font-mono text-slate-600 dark:text-slate-300">
                          ${op.projected_cost.toLocaleString()}
                        </td>
                        <td className="px-6 py-4 text-center">
                           <Badge color="gray">{t('operations_history_status_completed')}</Badge>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </Card>
      )}

      {/* Cost Estimation Modal */}
      <Modal isOpen={isEstimateModalOpen} onClose={() => setIsEstimateModalOpen(false)} title={t('operations_modal_title')}>
        <div className="space-y-6 max-h-[85vh] overflow-y-auto pr-2 custom-scrollbar">

          {/* Patient Safety Context Banner */}
          <div className="bg-red-50 dark:bg-red-900/10 p-3 rounded-lg border border-red-100 dark:border-red-900/30 flex items-start gap-3">
